import Link from "next/link";
import { createClient } from "@supabase/supabase-js";

const GOLD = "#C9A66B";
const BG   = "#0A0A0A";
const BG2  = "#111111";
const BG3  = "#1A1A1A";
const TX   = "#EDE9E0";
const TX2  = "rgba(237,233,224,0.7)";
const GD2  = "rgba(201,166,107,0.7)";
const SB   = createClient(process.env.NEXT_PUBLIC_SUPABASE_URL!, process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!);

export default function CardDetailPage() {
  const params = useParams();
  const id = params?.id as string;
  const [card,     setCard]     = useState<any>(null);
  const [listings, setListings] = useState<any[]>([]);
  const [similar,  setSimilar]  = useState<any[]>([]);
  const [history,  setHistory]  = useState<any[]>([]);
  const [sales,    setSales]    = useState<any[]>([]);
  const [loading,  setLoading]  = useState(true);
  const [added,    setAdded]    = useState(false);
  const [wished,   setWished]   = useState(false);

  useEffect(() => {
    if (!id) return;
    async function load() {
      const [{ data: c }, { data: l }] = await Promise.all([
        SB.from("cards").select("id,name,name_de,set_id,number,hp,types,rarity,is_holo,image_url,price_market,price_low,price_avg7,price_avg30,attacks,illustrator,regulation_mark,category,stage,scan_count").eq("id", id).single(),
        SB.from("marketplace_listings").select("id,price,condition,profiles!marketplace_listings_user_id_fkey(username)").eq("card_id", id).eq("is_active", true).order("price", { ascending: true }).limit(8),
      ]);
      setCard(c);
      setListings((l ?? []).map((x: any) => ({ ...x, profiles: Array.isArray(x.profiles) ? x.profiles[0] : x.profiles })));
      if (c?.set_id) {
        const { data: sim } = await SB.from("cards").select("id,name,name_de,image_url,price_market,number").eq("set_id", c.set_id).not("id","eq",id).not("price_market","is",null).order("price_market",{ascending:false}).limit(6);
        setSimilar(sim ?? []);
      }
      const { data: hist } = await SB.from("price_history").select("recorded_at,price_market").eq("card_id", id).order("recorded_at",{ascending:true}).limit(90);
      if (hist?.length) setHistory(hist.map((h: any) => ({ date: h.recorded_at, price: h.price_market })));
      const { data: sv } = await SB.from("escrow_transactions").select("amount,created_at,condition,profiles!escrow_transactions_buyer_id_fkey(username)").eq("card_id", id).eq("status","released").order("created_at",{ascending:false}).limit(10);
      if (sv?.length) setSales(sv.map((s: any) => ({ ...s, profiles: Array.isArray(s.profiles)?s.profiles[0]:s.profiles })));
      setLoading(false);
    }
    load();
  }, [id]);

  useEffect(() => {
    const link = document.createElement("link");
    link.rel = "stylesheet";
    link.href = "https://fonts.googleapis.com/css2?family=Playfair+Display:wght@400;500;700&family=Instrument+Sans:wght@400;500;600&display=swap";
    document.head.appendChild(link);
    return () => { try { document.head.removeChild(link); } catch {} };
  }, []);

  useEffect(() => {
    const el = document.getElementById("card-styles");
    if (el) return;
    const s = document.createElement("style");
    s.id = "card-styles";
    s.textContent = ".ph{font-family:'Playfair Display',serif;letter-spacing:-.05em}.btn-gold{display:inline-flex;align-items:center;gap:8px;padding:14px 28px;background:#C9A66B;color:#0A0A0A;border-radius:100px;border:none;font-size:14px;font-weight:600;cursor:pointer;text-decoration:none;transition:transform .2s;width:100%;justify-content:center}.btn-gold:hover{transform:scale(1.02)}.btn-outline{display:inline-flex;align-items:center;gap:8px;padding:13px 24px;border:1px solid rgba(201,166,107,.3);color:#C9A66B;border-radius:100px;background:transparent;font-size:14px;cursor:pointer;text-decoration:none;transition:all .2s;width:100%;justify-content:center}.btn-outline:hover{background:#C9A66B;color:#0A0A0A}.listing-row{display:flex;align-items:center;justify-content:space-between;gap:12px;padding:14px 18px;background:#1A1A1A;border-bottom:1px solid rgba(255,255,255,.05);transition:background .15s}.listing-row:hover{background:#1F1F1F}.listing-row:last-child{border-bottom:none}.sim-card{background:#111;border:1px solid rgba(255,255,255,.06);border-radius:16px;overflow:hidden;text-decoration:none;display:block;transition:transform .2s,border-color .2s}.sim-card:hover{transform:translateY(-4px);border-color:rgba(201,166,107,.25)}.attack-row{padding:16px 18px;background:#1A1A1A;border-bottom:1px solid rgba(255,255,255,.05)}.attack-row:last-child{border-bottom:none}.stat-cell{padding:16px;background:#111;border-right:1px solid rgba(255,255,255,.05);border-bottom:1px solid rgba(255,255,255,.05)}.breadcrumb-link{color:rgba(237,233,224,.4);text-decoration:none;font-size:13px;transition:color .15s}.breadcrumb-link:hover{color:#C9A66B}";
    document.head.appendChild(s);
    return () => { try { document.head.removeChild(s); } catch {} };
  }, []);

  async function addToPortfolio() {
    const { data: { user } } = await SB.auth.getUser();
    if (!user) { window.location.href = "/auth/login"; return; }
    await SB.from("user_collection").upsert({ user_id: user.id, card_id: id, quantity: 1, condition: "NM" }, { onConflict: "user_id,card_id" });
    setAdded(true);
  }

  async function addToWishlist() {
    const { data: { user } } = await SB.auth.getUser();
    if (!user) { window.location.href = "/auth/login"; return; }
    await SB.from("user_wishlist").upsert({ user_id: user.id, card_id: id }, { onConflict: "user_id,card_id" });
    setWished(true);
  }

  if (loading) return <div style={{ background: BG, minHeight: "100vh", display: "flex", alignItems: "center", justifyContent: "center", color: GD2 }}>Lade…</div>;
  if (!card)   return <div style={{ background: BG, minHeight: "100vh", display: "flex", alignItems: "center", justifyContent: "center" }}><Link href="/preischeck" style={{ color: GOLD }}>← Zurück</Link></div>;

  const imgSrc  = card.image_url ? (card.image_url.includes(".") ? card.image_url : card.image_url + "/high.webp") : null;
  const pct30   = card.price_avg30 && card.price_market ? ((card.price_market - card.price_avg30) / card.price_avg30 * 100) : null;
  const up30    = pct30 !== null && pct30 >= 0;
  const salesAvg = sales.length ? sales.reduce((s: number, x: any) => s + (x.amount ?? 0), 0) / sales.length : 0;

  return (
    <div style={{ background: BG, minHeight: "100vh", color: TX }}>
      <div style={{ maxWidth: 1280, margin: "0 auto", padding: "clamp(60px,8vw,100px) clamp(20px,4vw,48px)" }}>

        <div style={{ display: "flex", gap: 8, alignItems: "center", marginBottom: 48, fontSize: 13, color: "rgba(237,233,224,0.4)" }}>
          <Link href="/preischeck" className="breadcrumb-link">Preischeck</Link>
          <span>›</span>
          <Link href={"/sets/" + card.set_id} className="breadcrumb-link">{(card.set_id || "").toUpperCase()}</Link>
          <span>›</span>
          <span style={{ color: TX2 }}>{card.name_de || card.name}</span>
        </div>

        <div style={{ display: "grid", gridTemplateColumns: "380px 1fr", gap: 64, alignItems: "start" }}>

          <div>
            <div style={{ background: BG2, borderRadius: 24, overflow: "hidden", border: "1px solid rgba(201,166,107,0.15)", boxShadow: "0 40px 80px rgba(0,0,0,0.6)", marginBottom: 24 }}>
              <div style={{ padding: "24px 24px 0", background: BG3, display: "flex", justifyContent: "center" }}>
                <div style={{ width: "75%", aspectRatio: "3/4" }}>
                  {imgSrc
                    ? <img src={imgSrc} alt={card.name_de || card.name} style={{ width: "100%", height: "100%", objectFit: "contain" }} />
                    : <div style={{ width: "100%", height: "100%", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 48, opacity: 0.1 }}>◎</div>
                  }
                </div>
              </div>
              <div style={{ height: 1, background: "linear-gradient(90deg,transparent,rgba(201,166,107,0.3),transparent)" }} />
              <div style={{ padding: "14px 20px", display: "flex", justifyContent: "space-between" }}>
                <div style={{ fontSize: 11, color: "rgba(237,233,224,0.3)", textTransform: "uppercase", letterSpacing: "0.08em" }}>{(card.set_id || "").toUpperCase()} · #{card.number}</div>
                {card.scan_count > 0 && <div style={{ fontSize: 10, color: GD2 }}>⊙ {card.scan_count}× gescannt</div>}
              </div>
            </div>
            <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
              <button onClick={addToPortfolio} className="btn-gold" disabled={added} style={{ opacity: added ? 0.8 : 1 }}>
                {added ? "✓ Zur Sammlung hinzugefügt" : "+ Zu meiner Sammlung"}
              </button>
              <button onClick={addToWishlist} className="btn-outline" disabled={wished} style={{ opacity: wished ? 0.8 : 1 }}>
                {wished ? "✓ Auf Wunschliste" : "◉ Zur Wunschliste"}
              </button>
              <Link href={"/marketplace?sell=" + card.id} style={{ display: "flex", alignItems: "center", justifyContent: "center", padding: "13px 24px", borderRadius: 100, border: "1px solid rgba(255,255,255,0.1)", color: TX2, fontSize: 14, textDecoration: "none" }}>
                Inserieren →
              </Link>
            </div>
          </div>

          <div>
            <div style={{ display: "flex", gap: 8, marginBottom: 16, flexWrap: "wrap" }}>
              {card.rarity && <span style={{ padding: "4px 12px", borderRadius: 100, background: "rgba(201,166,107,0.1)", color: GOLD, fontSize: 11, fontWeight: 600, border: "1px solid rgba(201,166,107,0.2)" }}>{card.rarity}</span>}
              {card.is_holo && <span style={{ padding: "4px 12px", borderRadius: 100, background: "rgba(255,255,255,0.05)", color: TX2, fontSize: 11 }}>Holo</span>}
            </div>
            <h1 className="ph" style={{ fontSize: "clamp(32px,4vw,56px)", fontWeight: 500, color: TX, marginBottom: 8, lineHeight: 1 }}>{card.name_de || card.name}</h1>
            {card.name_de && card.name !== card.name_de && <div style={{ fontSize: 16, color: TX2, marginBottom: 32 }}>{card.name}</div>}

            <div style={{ background: BG2, borderRadius: 20, padding: "28px", marginBottom: 32, border: "1px solid rgba(201,166,107,0.12)", position: "relative", overflow: "hidden" }}>
              <div style={{ position: "absolute", top: 0, left: 0, right: 0, height: 1, background: "linear-gradient(90deg,transparent,rgba(201,166,107,0.3),transparent)" }} />
              <div style={{ fontSize: 11, letterSpacing: "0.14em", textTransform: "uppercase", color: GD2, marginBottom: 12 }}>Marktwert</div>
              <div className="ph" style={{ fontSize: "clamp(40px,5vw,64px)", fontWeight: 500, color: GOLD, lineHeight: 1, marginBottom: 16 }}>
                {card.price_market ? card.price_market.toLocaleString("de-DE", { minimumFractionDigits: 2 }) + " €" : "–"}
              </div>
              <div style={{ display: "flex", gap: 24, flexWrap: "wrap" }}>
                {card.price_low && <div><div style={{ fontSize: 10, color: GD2, marginBottom: 4, textTransform: "uppercase" }}>Ab</div><div style={{ fontFamily: "monospace", fontSize: 16, color: TX }}>{card.price_low.toFixed(2)} €</div></div>}
                {card.price_avg7 && <div><div style={{ fontSize: 10, color: GD2, marginBottom: 4, textTransform: "uppercase" }}>7-Tage-Ø</div><div style={{ fontFamily: "monospace", fontSize: 16, color: TX }}>{card.price_avg7.toFixed(2)} €</div></div>}
                {pct30 !== null && <div><div style={{ fontSize: 10, color: GD2, marginBottom: 4, textTransform: "uppercase" }}>30-Tage</div><div style={{ fontSize: 16, fontWeight: 700, color: up30 ? "#3db87a" : "#dc4a5a" }}>{up30 ? "▲" : "▼"} {Math.abs(pct30).toFixed(1)}%</div></div>}
              </div>
            </div>

            <div style={{ display: "grid", gridTemplateColumns: "repeat(3,1fr)", borderRadius: 16, overflow: "hidden", border: "1px solid rgba(255,255,255,0.06)", marginBottom: 32 }}>
              {[["HP",card.hp||"–"],["Typ",(card.types||[]).join(", ")||"–"],["Stufe",card.stage||"–"],["Kategorie",card.category||"–"],["Illustrator",card.illustrator||"–"],["Regulation",card.regulation_mark||"–"]].map(([l,v],i) => (
                <div key={l} className="stat-cell" style={{ borderRight: (i+1)%3===0 ? "none" : undefined, borderBottom: i>2 ? "none" : undefined }}>
                  <div style={{ fontSize: 9, fontWeight: 600, letterSpacing: "0.12em", textTransform: "uppercase", color: GD2, marginBottom: 4 }}>{l}</div>
                  <div style={{ fontSize: 13, color: TX, fontWeight: 500 }}>{v}</div>
                </div>
              ))}
            </div>

            {card.attacks?.length > 0 && (
              <div style={{ marginBottom: 32 }}>
                <div style={{ fontSize: 11, fontWeight: 600, letterSpacing: "0.14em", textTransform: "uppercase", color: GD2, marginBottom: 14 }}>Attacken</div>
                <div style={{ background: BG2, borderRadius: 16, overflow: "hidden", border: "1px solid rgba(255,255,255,0.06)" }}>
                  {card.attacks.map((atk: any, i: number) => (
                    <div key={i} className="attack-row">
                      <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 4 }}>
                        <span style={{ fontWeight: 600, fontSize: 14, color: TX }}>{atk.name}</span>
                        {atk.damage && <span style={{ fontFamily: "monospace", fontSize: 14, color: GOLD }}>{atk.damage}</span>}
                      </div>
                      {atk.text && <div style={{ fontSize: 13, color: TX2, lineHeight: 1.6 }}>{atk.text}</div>}
                    </div>
                  ))}
                </div>
              </div>
            )}

            {listings.length > 0 && (
              <div style={{ marginBottom: 32 }}>
                <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 14 }}>
                  <div style={{ fontSize: 11, fontWeight: 600, letterSpacing: "0.14em", textTransform: "uppercase", color: GD2 }}>Angebote</div>
                  <Link href="/marketplace" style={{ fontSize: 12, color: GOLD, textDecoration: "none" }}>Alle →</Link>
                </div>
                <div style={{ background: BG2, borderRadius: 16, overflow: "hidden", border: "1px solid rgba(201,166,107,0.1)" }}>
                  {listings.map((l: any) => (
                    <div key={l.id} className="listing-row">
                      <div><span style={{ fontSize: 13, fontWeight: 600, color: TX }}>@{l.profiles?.username ?? "Anonym"}</span><span style={{ fontSize: 11, color: TX2, marginLeft: 8 }}>{l.condition}</span></div>
                      <div style={{ fontFamily: "monospace", fontSize: 16, fontWeight: 600, color: GOLD }}>{l.price?.toFixed(2)} €</div>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>
        </div>

        {history.length > 1 && (
          <div style={{ marginTop: 48 }}>
            <div style={{ width: "100%", height: 1, background: "linear-gradient(90deg,transparent,rgba(201,166,107,0.2),transparent)", marginBottom: 32 }} />
            <div style={{ fontSize: 11, fontWeight: 600, letterSpacing: "0.14em", textTransform: "uppercase", color: GD2, marginBottom: 20 }}>Preisverlauf ({history.length} Tage)</div>
            <div style={{ background: BG2, borderRadius: 20, padding: "24px", border: "1px solid rgba(201,166,107,0.1)" }}>
              <PriceChart data={history} />
              <div style={{ display: "flex", justifyContent: "space-between", marginTop: 8, fontSize: 11, color: "rgba(237,233,224,0.35)" }}>
                <span>{history[0]?.date}</span>
                <span>{history[history.length - 1]?.date}</span>
              </div>
            </div>
          </div>
        )}

        {sales.length > 0 && (
          <div style={{ marginTop: 40 }}>
            <div style={{ fontSize: 11, fontWeight: 600, letterSpacing: "0.14em", textTransform: "uppercase", color: GD2, marginBottom: 16 }}>Abgeschlossene Verkäufe</div>
            <div style={{ background: BG2, borderRadius: 16, overflow: "hidden", border: "1px solid rgba(255,255,255,0.06)" }}>
              <div style={{ padding: "14px 20px", background: "rgba(201,166,107,0.06)", borderBottom: "1px solid rgba(255,255,255,0.05)", display: "flex", justifyContent: "space-between" }}>
                <span style={{ fontSize: 12, color: GD2 }}>Ø Verkaufspreis</span>
                <span className="ph" style={{ fontSize: 20, fontWeight: 500, color: GOLD }}>{salesAvg.toFixed(2)} €</span>
              </div>
              {sales.map((s: any, i: number) => (
                <div key={i} style={{ display: "flex", alignItems: "center", justifyContent: "space-between", padding: "12px 20px", borderBottom: "1px solid rgba(255,255,255,0.04)", fontSize: 13 }}>
                  <div style={{ color: TX2 }}>@{s.profiles?.username ?? "Anonym"} · {s.condition ?? "NM"}</div>
                  <div style={{ display: "flex", gap: 16, alignItems: "center" }}>
                    <span style={{ color: "rgba(237,233,224,0.35)", fontSize: 11 }}>{new Date(s.created_at).toLocaleDateString("de-DE")}</span>
                    <span style={{ fontFamily: "monospace", fontWeight: 600, color: GOLD }}>{s.amount?.toFixed(2)} €</span>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {similar.length > 0 && (
          <div style={{ marginTop: 64 }}>
            <div style={{ width: "100%", height: 1, background: "linear-gradient(90deg,transparent,rgba(201,166,107,0.2),transparent)", marginBottom: 40 }} />
            <div style={{ fontSize: 11, fontWeight: 600, letterSpacing: "0.14em", textTransform: "uppercase", color: GD2, marginBottom: 20 }}>Weitere Karten aus {(card.set_id || "").toUpperCase()}</div>
            <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill,minmax(160px,1fr))", gap: 16 }}>
              {similar.map((s: any) => {
                const sImg = s.image_url ? (s.image_url.includes(".") ? s.image_url : s.image_url + "/low.webp") : null;
                return (
                  <Link key={s.id} href={"/preischeck/" + s.id} className="sim-card">
                    <div style={{ aspectRatio: "3/4", background: BG3, display: "flex", alignItems: "center", justifyContent: "center", overflow: "hidden" }}>
                      {sImg && <img src={sImg} alt="" style={{ width: "85%", height: "85%", objectFit: "contain" }} loading="lazy" />}
                    </div>
                    <div style={{ padding: "10px 12px 14px" }}>
                      <div style={{ fontSize: 11, fontWeight: 600, color: TX, whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis", marginBottom: 4 }}>{s.name_de || s.name}</div>
                      <div style={{ fontFamily: "monospace", fontSize: 13, fontWeight: 600, color: GOLD }}>{s.price_market?.toFixed(2)} €</div>
                    </div>
                  </Link>
                );
              })}
            </div>
          </div>
        )}

      </div>
    </div>
  );
}

function PriceChart({ data }: { data: { date: string; price: number }[] }) {
  const W = 600, H = 120, PL = 8, PR = 8, PT = 8, PB = 4;
  const prices = data.map(d => d.price);
  const minP = Math.min(...prices);
  const maxP = Math.max(...prices);
  const rng  = maxP - minP || 1;
  const iw   = W - PL - PR;
  const ih   = H - PT - PB;
  const n    = data.length;
  const pts  = data.map((d, i) => (PL + (n > 1 ? i / (n-1) : 0) * iw).toFixed(1) + "," + (PT + (1-(d.price-minP)/rng)*ih).toFixed(1));
  const str  = pts.join(" L ");
  const last = data[data.length-1];
  const first = data[0];
  const up   = last.price >= first.price;
  const clr  = up ? "#3db87a" : "#dc4a5a";
  const lp   = pts[pts.length-1].split(",");
  const area = "M " + pts[0] + " L " + str + " L " + (PL+iw) + "," + (PT+ih) + " L " + PL + "," + (PT+ih) + " Z";
  const pct  = ((last.price-first.price)/first.price*100).toFixed(1);
  const diff = Math.abs(last.price-first.price).toFixed(2);
  const vb   = "0 0 " + W + " " + H;
  return (
    <div>
      <svg viewBox={vb} style={{ width: "100%", height: "auto" }}>
        <defs>
          <linearGradient id="pg" x1="0" y1="0" x2="0" y2="1">
            <stop offset="0%" stopColor={clr} stopOpacity={0.3} />
            <stop offset="100%" stopColor={clr} stopOpacity={0.02} />
          </linearGradient>
        </defs>
        <path d={area} fill="url(#pg)" />
        <path d={"M " + str} fill="none" stroke={clr} strokeWidth={1.5} strokeLinecap="round" strokeLinejoin="round" />
        <circle cx={lp[0]} cy={lp[1]} r={3} fill={clr} />
      </svg>
      <div style={{ display: "flex", justifyContent: "space-between", marginTop: 4 }}>
        <div style={{ fontSize: 11, color: "rgba(237,233,224,0.4)" }}>{minP.toFixed(2)} €</div>
        <div style={{ fontSize: 12, fontWeight: 600, color: clr }}>{up ? "▲" : "▼"} {diff} € ({pct}%)</div>
        <div style={{ fontSize: 11, color: "rgba(237,233,224,0.4)" }}>{maxP.toFixed(2)} €</div>
      </div>
    </div>
  );
}

files.page_scanner.tsx:
"use client";
import { useState, useRef, useCallback } from "react";
import Link from "next/link";
import { createClient } from "@supabase/supabase-js";

const GOLD = "#C9A66B";
const BG   = "#0A0A0A";
const BG2  = "#111111";
const BG3  = "#1A1A1A";
const TX   = "#EDE9E0";
const TX2  = "rgba(237,233,224,0.7)";
const GD2  = "rgba(201,166,107,0.7)";
const GD3  = "rgba(201,166,107,0.25)";
const GD4  = "rgba(201,166,107,0.1)";

const SB = createClient(
  process.env.NEXT_PUBLIC_SUPABASE_URL!,
  process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!
);

interface ScanResult {
  status: string;
  card?: {
    id: string; name: string; name_en: string; set_id: string;
    number: string; image_url: string | null; price_market: number | null;
    price_low: number | null; rarity: string | null; hp: string | null; scan_count: number;
  };
  confidence: number;
  error?: string; message?: string;
}

interface WishlistMatch {
  id: string;
  max_price: number | null;
  profiles: { username: string } | null;
}

export default function ScannerPage() {
  const [preview,  setPreview]  = useState<string | null>(null);
  const [scanning, setScanning] = useState(false);
  const [result,   setResult]   = useState<ScanResult | null>(null);
  const [matches,  setMatches]  = useState<WishlistMatch[]>([]);
  const [error,    setError]    = useState<string | null>(null);
  const [dragging, setDragging] = useState(false);
  const [added,    setAdded]    = useState(false);
  const [scanCount, setScanCount] = useState<number | null>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  const handleFile = useCallback(async (file: File) => {
    setError(null); setResult(null); setAdded(false); setMatches([]);
    setScanning(true);

    const reader = new FileReader();
    reader.onload = e => setPreview(e.target?.result as string);
    reader.readAsDataURL(file);

    const base64 = await new Promise<string>((res, rej) => {
      const r = new FileReader();
      r.onload  = () => res((r.result as string).split(",")[1]);
      r.onerror = rej;
      r.readAsDataURL(file);
    });

    try {
      const { data: { session } } = await SB.auth.getSession();
      const headers: Record<string, string> = { "Content-Type": "application/json" };
      if (session?.access_token) headers["Authorization"] = `Bearer ${session.access_token}`;

      // Check scan count for free users
      if (session?.user) {
        const today = new Date().toISOString().split("T")[0];
        const { count } = await SB.from("scan_logs")
          .select("id", { count: "exact", head: true })
          .eq("user_id", session.user.id)
          .gte("created_at", today + "T00:00:00Z");
        setScanCount(count ?? 0);
      }

      const res = await fetch("/api/scanner/scan", {
        method: "POST", headers,
        body: JSON.stringify({ imageBase64: base64, mimeType: file.type || "image/jpeg" }),
      });
      const data: ScanResult = await res.json();

      if (res.status === 429) {
        setError("Tageslimit von 5 Scans erreicht. Upgrade auf Premium für unlimitierte Scans.");
      } else if (!res.ok || data.error) {
        setError(data.message ?? "Karte konnte nicht erkannt werden. Bitte klareres Foto versuchen.");
      } else {
        setResult(data);
        // Check wishlist matches
        if (data.card?.id) {
          const { data: wm } = await SB
            .from("user_wishlist")
            .select("id, max_price, profiles!user_wishlist_user_id_fkey(username)")
            .eq("card_id", data.card.id)
            .limit(5);
          if (wm?.length) {
            setMatches(wm.map((m: any) => ({
              ...m,
              profiles: Array.isArray(m.profiles) ? m.profiles[0] : m.profiles,
            })));
          }
        }
      }
    } catch {
      setError("Verbindungsfehler. Bitte erneut versuchen.");
    }
    setScanning(false);
  }, []);

  async function addToPortfolio() {
    if (!result?.card) return;
    try {
      const { data: { user } } = await SB.auth.getUser();
      if (!user) { window.location.href = "/auth/login"; return; }
      await SB.from("user_collection").upsert(
        { user_id: user.id, card_id: result.card.id, quantity: 1, condition: "NM" },
        { onConflict: "user_id,card_id" }
      );
      setAdded(true);
    } catch { setError("Fehler beim Hinzufügen zum Portfolio."); }
  }

  const card   = result?.card;
  const imgSrc = card?.image_url
    ? (card.image_url.includes(".") ? card.image_url : card.image_url + "/high.webp")
    : null;

  return (
    <div style={{ background: BG, minHeight: "100vh", color: TX }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Playfair+Display:wght@400;500;700&family=Instrument+Sans:wght@400;500;600&display=swap');
        .ph { font-family: 'Playfair Display', serif; letter-spacing: -0.05em; }
        .upload-zone { border: 1.5px dashed rgba(201,166,107,0.3); border-radius: 20px; transition: border-color 0.2s, background 0.2s; cursor: pointer; }
        .upload-zone:hover, .upload-zone.drag { border-color: #C9A66B; background: rgba(201,166,107,0.04); }
        .btn-gold { display:inline-flex; align-items:center; gap:8px; padding:14px 28px; background:#C9A66B; color:#0A0A0A; border-radius:100px; border:none; font-size:14px; font-weight:600; cursor:pointer; text-decoration:none; transition:transform 0.2s,box-shadow 0.2s; }
        .btn-gold:hover { transform:scale(1.03); box-shadow:0 8px 32px rgba(201,166,107,0.35); }
        .btn-outline { display:inline-flex; align-items:center; gap:8px; padding:13px 24px; border:1px solid rgba(201,166,107,0.4); color:#C9A66B; border-radius:100px; background:transparent; font-size:14px; cursor:pointer; text-decoration:none; transition:all 0.2s; }
        .btn-outline:hover { background:#C9A66B; color:#0A0A0A; }
        .match-card { background:#111111; border:1px solid rgba(201,166,107,0.2); border-radius:16px; padding:16px 20px; display:flex; align-items:center; justify-content:space-between; gap:12px; transition:border-color 0.2s; }
        .match-card:hover { border-color:rgba(201,166,107,0.4); }
        @keyframes spin { to { transform:rotate(360deg); } }
        @keyframes fadeUp { from{opacity:0;transform:translateY(20px)} to{opacity:1;transform:translateY(0)} }
        .fade-up { animation: fadeUp 0.5s cubic-bezier(0.22,1,0.36,1) both; }
        .scan-line { position:absolute; left:0; right:0; height:2px; background:linear-gradient(90deg,transparent,rgba(201,166,107,0.6),transparent); animation:scanMove 1.5s ease-in-out infinite; }
        @keyframes scanMove { 0%{top:10%} 100%{top:90%} }
        @keyframes pulse { 0%,100%{opacity:1} 50%{opacity:0.4} }
      `}</style>

      <div style={{ maxWidth: 1200, margin: "0 auto", padding: "clamp(60px,8vw,100px) clamp(20px,4vw,48px)" }}>

        {/* Header */}
        <div style={{ marginBottom: 64 }}>
          <div style={{ fontSize: 11, fontWeight: 600, letterSpacing: "0.18em", textTransform: "uppercase", color: GD2, marginBottom: 16 }}>
            KI-Scanner
          </div>
          <h1 className="ph" style={{ fontSize: "clamp(40px,6vw,80px)", fontWeight: 500, color: TX, marginBottom: 16, lineHeight: 1 }}>
            Karte fotografieren.<br/><span style={{ color: GOLD }}>Wert sofort sehen.</span>
          </h1>
          <p style={{ fontSize: 16, color: TX2, maxWidth: 480 }}>
            Powered by Gemini AI · Erkennt jede Pokémon-Karte in Sekunden
          </p>
          {scanCount !== null && scanCount >= 3 && (
            <div style={{ marginTop: 16, padding: "10px 18px", background: "rgba(201,166,107,0.08)", border: "1px solid rgba(201,166,107,0.2)", borderRadius: 100, display: "inline-flex", alignItems: "center", gap: 8, fontSize: 13, color: GOLD }}>
              ✦ {5 - scanCount} von 5 Gratis-Scans übrig · <Link href="/dashboard/premium" style={{ color: GOLD, fontWeight: 600 }}>Premium für ∞</Link>
            </div>
          )}
        </div>

        <div style={{ display: "grid", gridTemplateColumns: card ? "1fr 1fr" : "1fr", gap: 48, maxWidth: card ? "100%" : 560, alignItems: "start" }}>

          {/* Upload Zone */}
          <div>
            <input ref={inputRef} type="file" accept="image/*" style={{ display: "none" }}
              onChange={e => e.target.files?.[0] && handleFile(e.target.files[0])} />

            <div
              className={`upload-zone${dragging ? " drag" : ""}`}
              onClick={() => !scanning && inputRef.current?.click()}
              onDragOver={e => { e.preventDefault(); setDragging(true); }}
              onDragLeave={() => setDragging(false)}
              onDrop={e => { e.preventDefault(); setDragging(false); e.dataTransfer.files[0] && handleFile(e.dataTransfer.files[0]); }}
              style={{
                aspectRatio: preview ? "3/4" : "4/3",
                display: "flex", alignItems: "center", justifyContent: "center",
                overflow: "hidden", position: "relative",
                background: preview ? "transparent" : BG2,
              }}
            >
              {preview ? (
                <img src={preview} alt="Vorschau" style={{ width: "100%", height: "100%", objectFit: "contain" }} />
              ) : (
                <div style={{ textAlign: "center", padding: 40 }}>
                  <div style={{ fontSize: 56, color: GOLD, opacity: 0.3, marginBottom: 20 }}>⊙</div>
                  <div style={{ fontSize: 17, fontWeight: 500, color: TX, marginBottom: 8 }}>Karte hochladen</div>
                  <div style={{ fontSize: 13, color: TX2 }}>Drag & Drop oder klicken</div>
                  <div style={{ fontSize: 11, color: "rgba(237,233,224,0.4)", marginTop: 8 }}>JPG, PNG, HEIC</div>
                </div>
              )}

              {/* Scanning overlay */}
              {scanning && (
                <div style={{ position: "absolute", inset: 0, background: "rgba(10,10,10,0.85)", display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", gap: 20 }}>
                  <div className="scan-line"/>
                  <div style={{ width: 44, height: 44, borderRadius: "50%", border: "2px solid rgba(201,166,107,0.2)", borderTopColor: GOLD, animation: "spin 0.8s linear infinite" }}/>
                  <div style={{ fontSize: 14, color: GD2, letterSpacing: "0.1em" }}>Analysiere Karte…</div>
                </div>
              )}
            </div>

            <div style={{ marginTop: 16, display: "flex", gap: 10 }}>
              <button onClick={() => inputRef.current?.click()} disabled={scanning} className="btn-gold"
                style={{ flex: 1, justifyContent: "center", opacity: scanning ? 0.5 : 1 }}>
                {scanning ? "Analysiere…" : preview ? "Neues Foto" : "Foto auswählen"}
              </button>
              {preview && !scanning && (
                <button onClick={() => { setPreview(null); setResult(null); setError(null); setMatches([]); }}
                  className="btn-outline" style={{ padding: "13px 20px" }}>✕</button>
              )}
            </div>

            {error && (
              <div style={{ marginTop: 16, padding: "14px 18px", background: "rgba(220,74,90,0.08)", border: "1px solid rgba(220,74,90,0.2)", borderRadius: 12, fontSize: 13, color: "#dc4a5a" }}>
                {error}
              </div>
            )}
          </div>

          {/* Result */}
          {card && (
            <div className="fade-up">
              {/* Card display */}
              <div style={{
                background: BG2, borderRadius: 24, overflow: "hidden",
                border: "1px solid rgba(201,166,107,0.2)",
                boxShadow: "0 24px 60px rgba(0,0,0,0.5)",
                marginBottom: 28,
              }}>
                {/* Image */}
                <div style={{ background: BG3, padding: "24px 24px 0", display: "flex", justifyContent: "center" }}>
                  <div style={{ width: "60%", aspectRatio: "3/4", position: "relative" }}>
                    {imgSrc ? (
                      <img src={imgSrc} alt={card.name} style={{ width: "100%", height: "100%", objectFit: "contain" }} />
                    ) : (
                      <div style={{ width: "100%", height: "100%", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 48, opacity: 0.2 }}>◎</div>
                    )}
                  </div>
                </div>

                {/* Info */}
                <div style={{ padding: "24px 28px 28px" }}>
                  {/* Confidence badge */}
                  <div style={{ marginBottom: 12 }}>
                    <span style={{ padding: "3px 12px", borderRadius: 100, background: "rgba(201,166,107,0.1)", color: GOLD, fontSize: 10, fontWeight: 700, letterSpacing: "0.1em", border: "1px solid rgba(201,166,107,0.2)" }}>
                      ✓ ERKANNT · {result?.confidence ?? 0}% Konfidenz
                    </span>
                  </div>

                  <h2 className="ph" style={{ fontSize: "clamp(22px,3vw,32px)", fontWeight: 500, color: TX, marginBottom: 6 }}>
                    {card.name}
                  </h2>
                  <div style={{ fontSize: 12, color: TX2, marginBottom: 20, textTransform: "uppercase", letterSpacing: "0.08em" }}>
                    {card.set_id?.toUpperCase()} · #{card.number}{card.rarity ? ` · ${card.rarity}` : ""}
                  </div>

                  {card.price_market && (
                    <div style={{ marginBottom: 24 }}>
                      <div style={{ fontSize: 11, letterSpacing: "0.12em", textTransform: "uppercase", color: GD2, marginBottom: 6 }}>Marktwert</div>
                      <div className="ph" style={{ fontSize: "clamp(32px,4vw,48px)", fontWeight: 500, color: GOLD, lineHeight: 1 }}>
                        {card.price_market.toLocaleString("de-DE", { minimumFractionDigits: 2 })} €
                      </div>
                      {card.price_low && (
                        <div style={{ fontSize: 13, color: TX2, marginTop: 4 }}>
                          Ab {card.price_low.toLocaleString("de-DE", { minimumFractionDigits: 2 })} € verfügbar
                        </div>
                      )}
                    </div>
                  )}

                  {/* Actions */}
                  <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
                    <Link href={`/preischeck/${card.id}`} className="btn-gold" style={{ justifyContent: "center" }}>
                      Kartendetails ansehen
                    </Link>
                    <button onClick={addToPortfolio} disabled={added} style={{
                      padding: "13px 24px", borderRadius: 100, border: "1px solid rgba(201,166,107,0.3)",
                      background: added ? "rgba(201,166,107,0.1)" : "transparent",
                      color: added ? GOLD : TX2, fontSize: 14, cursor: added ? "default" : "pointer",
                      transition: "all 0.2s",
                    }}>
                      {added ? "✓ Portfolio hinzugefügt" : "+ Zu meiner Sammlung"}
                    </button>
                    <Link href={`/marketplace?sell=${card.id}`} style={{
                      padding: "13px 24px", borderRadius: 100, border: "1px solid rgba(255,255,255,0.1)",
                      color: TX2, fontSize: 14, textDecoration: "none", textAlign: "center",
                      transition: "all 0.2s",
                    }}>
                      Auf Marktplatz inserieren →
                    </Link>
                  </div>
                </div>
              </div>

              {/* Wishlist Matches */}
              {matches.length > 0 && (
                <div style={{ background: BG2, borderRadius: 20, border: "1px solid rgba(201,166,107,0.3)", overflow: "hidden", boxShadow: "0 0 0 1px rgba(201,166,107,0.1)" }}>
                  {/* Top gold line */}
                  <div style={{ height: 1, background: "linear-gradient(90deg,transparent,rgba(201,166,107,0.5),transparent)" }}/>
                  <div style={{ padding: "20px 24px 16px" }}>
                    <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 16 }}>
                      <span style={{ fontSize: 18, color: GOLD }}>✦</span>
                      <div>
                        <div style={{ fontSize: 14, fontWeight: 600, color: TX }}>
                          {matches.length} {matches.length === 1 ? "Sammler sucht" : "Sammler suchen"} diese Karte!
                        </div>
                        <div style={{ fontSize: 12, color: TX2 }}>Direkt verkaufen zum Wunschpreis</div>
                      </div>
                    </div>
                    <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
                      {matches.map(m => (
                        <div key={m.id} className="match-card">
                          <div>
                            <div style={{ fontSize: 13, fontWeight: 600, color: TX }}>@{m.profiles?.username ?? "Sammler"}</div>
                            {m.max_price && (
                              <div style={{ fontSize: 12, color: GD2 }}>
                                Zahlt bis {m.max_price.toLocaleString("de-DE", { minimumFractionDigits: 2 })} €
                              </div>
                            )}
                          </div>
                          <Link href={`/marketplace?sell=${card.id}`} className="btn-gold" style={{ padding: "10px 20px", fontSize: 13 }}>
                            Verkaufen ✦
                          </Link>
                        </div>
                      ))}
                    </div>
                  </div>
                </div>
              )}
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

