"use client";
import { useState, useEffect, useRef } from "react";
import Link from "next/link";
import { createClient } from "@supabase/supabase-js";

const GOLD = "#C9A66B";
const BG   = "#0A0A0A";
const BG2  = "#111111";
const BG3  = "#1A1A1A";
const TX   = "#EDE9E0";
const TX2  = "rgba(237,233,224,0.7)";
const GD2  = "rgba(201,166,107,0.7)";

const SB = createClient(
  process.env.NEXT_PUBLIC_SUPABASE_URL!,
  process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!
);

function timeAgo(date: string) {
  const m = Math.floor((Date.now() - new Date(date).getTime()) / 60000);
  if (m < 1)    return "gerade eben";
  if (m < 60)   return `${m} Min.`;
  if (m < 1440) return `${Math.floor(m / 60)} Std.`;
  return `${Math.floor(m / 1440)}d`;
}

export default function ForumPage() {
  const [posts,   setPosts]   = useState<any[]>([]);
  const [cats,    setCats]    = useState<any[]>([]);
  const [catId,   setCatId]   = useState<string | null>(null);
  const [loading, setLoading] = useState(true);
  const [user,    setUser]    = useState<any>(null);
  const [showNew, setShowNew] = useState(false);
  const channelRef = useRef<any>(null);

  useEffect(() => {
    SB.auth.getSession().then(({ data: { session } }) => setUser(session?.user ?? null));
    SB.from("forum_categories").select("id,name,slug,icon").order("name")
      .then(({ data }) => {
        if (data?.length) {
          setCats(data);
        } else {
          // Fallback categories if table is empty
          setCats([
            { id: null, name: "Allgemein",    slug: "allgemein",    icon: "💬" },
            { id: null, name: "Preise",        slug: "preise",       icon: "📈" },
            { id: null, name: "Suche/Biete",   slug: "suche-biete",  icon: "🔄" },
            { id: null, name: "Neuheiten",     slug: "neuheiten",    icon: "✨" },
            { id: null, name: "Grading",       slug: "grading",      icon: "🏆" },
          ]);
        }
      });
    loadPosts(null);

    channelRef.current = SB.channel("forum_realtime")
      .on("postgres_changes", { event: "*", schema: "public", table: "forum_posts" }, () => loadPosts(catId))
      .subscribe();
    return () => { channelRef.current?.unsubscribe(); };
  }, []);

  useEffect(() => { loadPosts(catId); }, [catId]);

  async function loadPosts(categoryId: string | null) {
    setLoading(true);
    try {
      let q = SB.from("forum_posts")
        .select(`id,title,upvotes,created_at,card_id,
          profiles!forum_posts_user_id_fkey(username),
          forum_categories!forum_posts_category_id_fkey(name,slug),
          cards!forum_posts_card_id_fkey(name,name_de,image_url)`)
        .eq("is_deleted", false)
        .order("created_at", { ascending: false })
        .limit(40);
      if (categoryId) q = q.eq("category_id", categoryId);
      const { data } = await q;
      setPosts((data ?? []).map((p: any) => ({
        ...p,
        profiles:         Array.isArray(p.profiles)         ? p.profiles[0]         : p.profiles,
        forum_categories: Array.isArray(p.forum_categories) ? p.forum_categories[0] : p.forum_categories,
        cards:            Array.isArray(p.cards)            ? p.cards[0]            : p.cards,
      })));
    } catch {}
    setLoading(false);
  }

  async function upvote(postId: string, current: number) {
    if (!user) { window.location.href = "/auth/login"; return; }
    try {
      await SB.from("forum_posts").update({ upvotes: current + 1 }).eq("id", postId);
      setPosts(prev => prev.map(p => p.id === postId ? { ...p, upvotes: p.upvotes + 1 } : p));
    } catch {}
  }

  return (
    <div style={{ background: BG, minHeight: "100vh", color: TX }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Playfair+Display:wght@400;500;700&family=Instrument+Sans:wght@400;500;600&display=swap');
        .ph { font-family:'Playfair Display',serif; letter-spacing:-0.05em; }
        .post-row { background:#111111; border:1px solid rgba(255,255,255,0.06); border-radius:16px; overflow:hidden; transition:border-color 0.2s,transform 0.2s; cursor:pointer; }
        .post-row:hover { border-color:rgba(201,166,107,0.25); transform:translateY(-1px); }
        .cat-btn { padding:9px 18px; border-radius:100px; border:1px solid transparent; font-size:13px; cursor:pointer; transition:all 0.2s; background:transparent; }
        .cat-btn.active { background:rgba(201,166,107,0.1); border-color:rgba(201,166,107,0.3); color:#C9A66B; font-weight:600; }
        .cat-btn:not(.active) { color:rgba(237,233,224,0.5); }
        .cat-btn:not(.active):hover { color:#EDE9E0; background:rgba(255,255,255,0.04); }
        .btn-gold { display:inline-flex; align-items:center; gap:8px; padding:12px 24px; background:#C9A66B; color:#0A0A0A; border-radius:100px; border:none; font-size:13px; font-weight:600; cursor:pointer; text-decoration:none; transition:transform 0.2s; }
        .btn-gold:hover { transform:scale(1.03); }
        .vote-btn { display:flex; flex-direction:column; align-items:center; justify-content:center; gap:3px; padding:0 20px; background:transparent; border:none; border-right:1px solid rgba(255,255,255,0.06); cursor:pointer; min-width:60px; flex-shrink:0; transition:background 0.15s; }
        .vote-btn:hover { background:rgba(201,166,107,0.06); }
        @keyframes fadeUp { from{opacity:0;transform:translateY(16px)} to{opacity:1;transform:translateY(0)} }
        .fade-up { animation:fadeUp 0.4s cubic-bezier(0.22,1,0.36,1) both; }
        .live-dot { width:7px; height:7px; border-radius:50%; background:#3db87a; animation:livePulse 2s ease-in-out infinite; }
        @keyframes livePulse { 0%,100%{opacity:1;box-shadow:0 0 0 0 rgba(61,184,122,0)} 50%{opacity:0.7;box-shadow:0 0 0 4px rgba(61,184,122,0.1)} }
      `}</style>

      <div style={{ maxWidth: 1280, margin: "0 auto", padding: "clamp(60px,8vw,100px) clamp(20px,4vw,48px)" }}>

        {/* Header */}
        <div style={{ marginBottom: 56, display: "flex", justifyContent: "space-between", alignItems: "flex-end", flexWrap: "wrap", gap: 20 }}>
          <div>
            <div style={{ fontSize: 11, fontWeight: 600, letterSpacing: "0.18em", textTransform: "uppercase", color: GD2, marginBottom: 16 }}>Community</div>
            <h1 className="ph" style={{ fontSize: "clamp(36px,5vw,72px)", fontWeight: 500, color: TX, lineHeight: 1 }}>
              Forum &<br/><span style={{ color: GOLD }}>Austausch</span>
            </h1>
          </div>
          <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
            <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
              <div className="live-dot"/>
              <span style={{ fontSize: 11, color: TX2 }}>Live</span>
            </div>
            <button onClick={() => { if (!user) { window.location.href = "/auth/login"; return; } setShowNew(true); }}
              className="btn-gold">+ Beitrag erstellen</button>
          </div>
        </div>

        <div style={{ display: "grid", gridTemplateColumns: "240px 1fr", gap: 48, alignItems: "start" }}>

          {/* Sidebar */}
          <div style={{ position: "sticky", top: 100 }}>
            <div style={{ fontSize: 10, fontWeight: 600, letterSpacing: "0.14em", textTransform: "uppercase", color: GD2, marginBottom: 12 }}>Kategorien</div>
            <div style={{ display: "flex", flexDirection: "column", gap: 4 }}>
              <button className={`cat-btn${catId === null ? " active" : ""}`} onClick={() => setCatId(null)}>
                Alle Beiträge
              </button>
              {cats.map(cat => (
                <button key={cat.id} className={`cat-btn${catId === cat.id ? " active" : ""}`} onClick={() => setCatId(cat.id)}>
                  {cat.icon && <span style={{ marginRight: 6 }}>{cat.icon}</span>}
                  {cat.name}
                </button>
              ))}
            </div>

            {/* Stats */}
            <div style={{ marginTop: 32, padding: "20px", background: BG2, borderRadius: 16, border: "1px solid rgba(201,166,107,0.1)" }}>
              <div style={{ fontSize: 10, letterSpacing: "0.14em", textTransform: "uppercase", color: GD2, marginBottom: 12 }}>Community</div>
              <div style={{ fontSize: 28, fontWeight: 500, color: GOLD, fontFamily: "'Playfair Display', serif" }}>{posts.length}</div>
              <div style={{ fontSize: 12, color: TX2 }}>Aktive Beiträge</div>
            </div>
          </div>

          {/* Posts */}
          <div>
            {loading ? (
              <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
                {Array.from({ length: 5 }).map((_, i) => (
                  <div key={i} style={{ height: 90, background: BG2, borderRadius: 16, opacity: 0.4, animation: "fadeUp 1.5s ease-in-out infinite" }}/>
                ))}
              </div>
            ) : posts.length === 0 ? (
              <div style={{ textAlign: "center", padding: "80px 20px" }}>
                <div style={{ fontSize: 48, opacity: 0.15, marginBottom: 16, color: GOLD }}>◉</div>
                <div style={{ fontSize: 18, color: TX2, marginBottom: 24 }}>Noch keine Beiträge</div>
                <button onClick={() => setShowNew(true)} className="btn-gold">Ersten Beitrag erstellen</button>
              </div>
            ) : (
              <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
                {posts.map((post, i) => {
                  const imgSrc = post.cards?.image_url?.includes(".") ? post.cards.image_url : (post.cards?.image_url ? post.cards.image_url + "/low.webp" : null);
                  return (
                    <div key={post.id} className="post-row fade-up" style={{ animationDelay: `${i * 30}ms`, display: "flex" }}>
                      {/* Vote */}
                      <button className="vote-btn" onClick={() => upvote(post.id, post.upvotes)}>
                        <span style={{ fontSize: 12, color: GD2 }}>▲</span>
                        <span style={{ fontFamily: "monospace", fontSize: 14, fontWeight: 600, color: TX }}>{post.upvotes}</span>
                      </button>

                      {/* Content */}
                      <Link href={`/forum/post/${post.id}`} style={{ textDecoration: "none", flex: 1, padding: "16px 20px", display: "flex", gap: 14 }}>
                        {imgSrc && (
                          <div style={{ width: 40, height: 56, borderRadius: 6, overflow: "hidden", background: BG3, flexShrink: 0, border: "1px solid rgba(255,255,255,0.06)" }}>
                            <img src={imgSrc} alt="" style={{ width: "100%", height: "100%", objectFit: "contain" }}/>
                          </div>
                        )}
                        <div style={{ flex: 1, minWidth: 0 }}>
                          <div style={{ display: "flex", gap: 8, alignItems: "center", marginBottom: 6, flexWrap: "wrap" }}>
                            {post.forum_categories && (
                              <span style={{ padding: "2px 10px", borderRadius: 100, background: "rgba(201,166,107,0.08)", color: GD2, fontSize: 10, fontWeight: 600, letterSpacing: "0.08em", textTransform: "uppercase", border: "1px solid rgba(201,166,107,0.15)" }}>
                                {post.forum_categories.name}
                              </span>
                            )}
                          </div>
                          <div style={{ fontSize: 15, fontWeight: 600, color: TX, marginBottom: 4, lineHeight: 1.3 }}>{post.title}</div>
                          {(post.body || post.content) && (
                            <div style={{ fontSize: 13, color: TX2, overflow: "hidden", display: "-webkit-box", WebkitLineClamp: 2, WebkitBoxOrient: "vertical", lineHeight: 1.6 }}>
                              {post.body || post.content}
                            </div>
                          )}
                          <div style={{ marginTop: 8, display: "flex", gap: 12, fontSize: 11, color: "rgba(237,233,224,0.35)" }}>
                            <span>@{post.profiles?.username ?? "Anonym"}</span>
                            <span>vor {timeAgo(post.created_at)}</span>
                            {post.cards && <span style={{ color: GD2 }}>◎ {post.cards.name_de || post.cards.name}</span>}
                          </div>
                        </div>
                      </Link>
                    </div>
                  );
                })}
              </div>
            )}
          </div>
        </div>
      </div>

      {showNew && <NewPostModal cats={cats} onClose={() => setShowNew(false)} onCreated={() => { setShowNew(false); loadPosts(catId); }}/>}
    </div>
  );
}

function NewPostModal({ cats, onClose, onCreated }: { cats: any[]; onClose: () => void; onCreated: () => void }) {
  const [title, setTitle] = useState("");
  const [body,  setBody]  = useState("");
  const [catId, setCatId] = useState<string | null>(cats[0]?.id ?? null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  async function submit() {
    if (!title.trim()) { setError("Bitte einen Titel eingeben."); return; }
    setLoading(true);
    try {
      const { data: { session } } = await SB.auth.getSession();
      if (!session) { window.location.href = "/auth/login"; return; }
      const bodyText = body.trim() || null;
      // Try all possible column name combinations
      const attempts = [
        { user_id: session.user.id, title: title.trim(), content: bodyText, category_id: (catId && catId.length > 10) ? catId : null, upvotes: 0, is_deleted: false },
        { user_id: session.user.id, title: title.trim(), body: bodyText,    category_id: (catId && catId.length > 10) ? catId : null, upvotes: 0, is_deleted: false },
        { author_id: session.user.id, title: title.trim(), content: bodyText, category_id: (catId && catId.length > 10) ? catId : null, upvotes: 0 },
        { author_id: session.user.id, title: title.trim(), body: bodyText,    category_id: (catId && catId.length > 10) ? catId : null, upvotes: 0 },
        { user_id: session.user.id, title: title.trim(), category_id: (catId && catId.length > 10) ? catId : null, upvotes: 0 },
      ];
      let e: any = null;
      for (const attempt of attempts) {
        const result = await SB.from("forum_posts").insert(attempt);
        if (!result.error) { e = null; break; }
        e = result.error;
        if (!result.error.message?.includes("column")) break;
      }
      if (e) { setError(e.message); setLoading(false); return; }
      onCreated();
    } catch (e: any) { setError(e.message); }
    setLoading(false);
  }

  return (
    <div style={{ position: "fixed", inset: 0, background: "rgba(0,0,0,0.75)", display: "flex", alignItems: "center", justifyContent: "center", zIndex: 200, padding: 20 }}
      onClick={e => e.target === e.currentTarget && onClose()}>
      <div style={{ background: "#111111", borderRadius: 24, width: "100%", maxWidth: 540, padding: 36, position: "relative", border: "1px solid rgba(201,166,107,0.2)" }}>
        <div style={{ position: "absolute", top: 0, left: "20%", right: "20%", height: 1, background: "linear-gradient(90deg,transparent,rgba(201,166,107,0.4),transparent)" }}/>
        <button onClick={onClose} style={{ position: "absolute", top: 16, right: 16, background: "none", border: "none", fontSize: 22, cursor: "pointer", color: TX2 }}>×</button>
        <h2 className="ph" style={{ fontSize: 28, fontWeight: 500, marginBottom: 24, color: TX }}>Neuer Beitrag</h2>

        <div style={{ marginBottom: 16 }}>
          <div style={{ fontSize: 11, letterSpacing: "0.12em", textTransform: "uppercase", color: GD2, marginBottom: 8 }}>Kategorie</div>
          <div style={{ display: "flex", gap: 6, flexWrap: "wrap" }}>
            {cats.map(cat => (
              <button key={cat.id} onClick={() => setCatId(cat.id)} style={{
                padding: "7px 16px", borderRadius: 100, fontSize: 12, fontWeight: 500, cursor: "pointer",
                border: "1px solid", transition: "all 0.15s",
                borderColor: catId === cat.id ? "rgba(201,166,107,0.4)" : "rgba(255,255,255,0.1)",
                background: catId === cat.id ? "rgba(201,166,107,0.1)" : "transparent",
                color: catId === cat.id ? GOLD : TX2,
              }}>{cat.icon && cat.icon + " "}{cat.name}</button>
            ))}
          </div>
        </div>

        <div style={{ marginBottom: 16 }}>
          <div style={{ fontSize: 11, letterSpacing: "0.12em", textTransform: "uppercase", color: GD2, marginBottom: 8 }}>Titel</div>
          <input value={title} onChange={e => setTitle(e.target.value)} maxLength={120}
            placeholder="Worum geht es?"
            style={{ width: "100%", padding: "14px 18px", background: "rgba(255,255,255,0.04)", border: "1px solid rgba(255,255,255,0.1)", borderRadius: 12, color: TX, fontSize: 15, outline: "none", fontFamily: "inherit" }}/>
        </div>

        <div style={{ marginBottom: 24 }}>
          <div style={{ fontSize: 11, letterSpacing: "0.12em", textTransform: "uppercase", color: GD2, marginBottom: 8 }}>Inhalt</div>
          <textarea value={body} onChange={e => setBody(e.target.value)} rows={4}
            placeholder="Schreib mehr dazu…"
            style={{ width: "100%", padding: "14px 18px", background: "rgba(255,255,255,0.04)", border: "1px solid rgba(255,255,255,0.1)", borderRadius: 12, color: TX, fontSize: 15, outline: "none", resize: "vertical", minHeight: 100, fontFamily: "inherit" }}/>
        </div>

        {error && <div style={{ marginBottom: 16, fontSize: 13, color: "#dc4a5a" }}>{error}</div>}

        <button onClick={submit} disabled={loading || !title.trim()}
          className="btn-gold" style={{ width: "100%", justifyContent: "center", opacity: loading || !title.trim() ? 0.5 : 1 }}>
          {loading ? "Veröffentliche…" : "Beitrag veröffentlichen"}
        </button>
      </div>
    </div>
  );
}

files.page_marketplace.tsx:
"use client";
import { useState, useEffect, useCallback } from "react";
import Link from "next/link";
import { createClient } from "@supabase/supabase-js";

const GOLD = "#C9A66B";
const BG   = "#0A0A0A";
const BG2  = "#111111";
const BG3  = "#1A1A1A";
const TX   = "#EDE9E0";
const TX2  = "rgba(237,233,224,0.7)";
const GD2  = "rgba(201,166,107,0.7)";

const SB = createClient(
  process.env.NEXT_PUBLIC_SUPABASE_URL!,
  process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!
);

interface Listing {
  id: string; type: "offer"|"want"; price: number|null;
  condition: string; note: string; card_id: string;
  profiles: { username: string }|null;
  cards: { id:string; name:string; name_de:string|null; set_id:string; number:string; image_url:string|null; price_market:number|null }|null;
}

export default function MarketplacePage() {
  const [listings,   setListings]   = useState<Listing[]>([]);
  const [tab,        setTab]        = useState<"offer"|"want">("offer");
  const [loading,    setLoading]    = useState(true);
  const [showCreate, setShowCreate] = useState(false);
  const [user,       setUser]       = useState<any>(null);
  const [presellId,  setPresellId]  = useState<string|null>(null);

  useEffect(() => {
    const params = new URLSearchParams(window.location.search);
    const sell = params.get("sell");
    if (sell) { setPresellId(sell); setShowCreate(true); }
    SB.auth.getSession().then(({ data: { session } }) => setUser(session?.user ?? null));
  }, []);

  const loadListings = useCallback(async () => {
    setLoading(true);
    try {
      const res = await fetch(`/api/marketplace?type=${tab}&limit=24`);
      const data = await res.json();
      setListings(data.listings ?? []);
    } catch {}
    setLoading(false);
  }, [tab]);

  useEffect(() => { loadListings(); }, [loadListings]);

  return (
    <div style={{ background: BG, minHeight: "100vh", color: TX }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Playfair+Display:wght@400;500;700&family=Instrument+Sans:wght@400;500;600&display=swap');
        .ph { font-family:'Playfair Display',serif; letter-spacing:-0.05em; }
        .listing-card { background:#111111; border:1px solid rgba(255,255,255,0.07); border-radius:20px; overflow:hidden; transition:transform 0.25s cubic-bezier(0.22,1,0.36,1),border-color 0.2s,box-shadow 0.25s; }
        .listing-card:hover { transform:translateY(-4px); border-color:rgba(201,166,107,0.25); box-shadow:0 20px 50px rgba(0,0,0,0.5); }
        .listing-card.deal { border-color:rgba(201,166,107,0.3); background:linear-gradient(135deg,rgba(201,166,107,0.05),#111111); }
        .tab-btn { padding:10px 28px; border-radius:100px; border:1px solid transparent; font-size:14px; cursor:pointer; transition:all 0.2s; background:transparent; }
        .tab-btn.active { background:rgba(201,166,107,0.1); border-color:rgba(201,166,107,0.3); color:#C9A66B; font-weight:600; }
        .tab-btn:not(.active) { color:rgba(237,233,224,0.5); }
        .tab-btn:not(.active):hover { color:#EDE9E0; }
        .btn-gold { display:inline-flex; align-items:center; gap:8px; padding:13px 26px; background:#C9A66B; color:#0A0A0A; border-radius:100px; border:none; font-size:14px; font-weight:600; cursor:pointer; text-decoration:none; transition:transform 0.2s,box-shadow 0.2s; }
        .btn-gold:hover { transform:scale(1.03); box-shadow:0 8px 32px rgba(201,166,107,0.3); }
        @keyframes skeleton { 0%,100%{opacity:.3} 50%{opacity:.6} }
        .skel { animation:skeleton 1.5s ease-in-out infinite; background:#111; border-radius:20px; }
        @keyframes fadeUp { from{opacity:0;transform:translateY(16px)} to{opacity:1;transform:translateY(0)} }
        .fade-up { animation:fadeUp 0.4s cubic-bezier(0.22,1,0.36,1) both; }
      `}</style>

      <div style={{ maxWidth: 1400, margin: "0 auto", padding: "clamp(60px,8vw,100px) clamp(20px,4vw,48px)" }}>

        {/* Header */}
        <div style={{ marginBottom: 56, display: "flex", justifyContent: "space-between", alignItems: "flex-end", flexWrap: "wrap", gap: 20 }}>
          <div>
            <div style={{ fontSize: 11, fontWeight: 600, letterSpacing: "0.16em", textTransform: "uppercase", color: GD2, marginBottom: 16 }}>
              Escrow-gesicherter Handel
            </div>
            <h1 className="ph" style={{ fontSize: "clamp(40px,6vw,80px)", fontWeight: 500, color: TX, lineHeight: 1 }}>
              Marktplatz
            </h1>
          </div>
          <button onClick={() => { if (!user) { window.location.href = "/auth/login"; return; } setShowCreate(true); }}
            className="btn-gold" style={{ fontSize: 15 }}>
            + Inserieren ✦
          </button>
        </div>

        {/* Escrow info */}
        <div style={{ padding: "16px 24px", marginBottom: 40, background: "rgba(201,166,107,0.06)", border: "1px solid rgba(201,166,107,0.2)", borderRadius: 100, display: "inline-flex", alignItems: "center", gap: 12, fontSize: 13, color: GD2 }}>
          <span style={{ fontSize: 18 }}>✦</span>
          <span>Sicher via pokédax Escrow — Geld wird erst freigegeben wenn du den Erhalt bestätigst.</span>
        </div>

        {/* Tabs */}
        <div style={{ display: "flex", gap: 8, marginBottom: 48 }}>
          {(["offer","want"] as const).map(t => (
            <button key={t} className={`tab-btn${tab===t?" active":""}`} onClick={() => setTab(t)}>
              {t === "offer" ? "Angebote" : "Gesuche"}
            </button>
          ))}
        </div>

        {/* Grid */}
        {loading ? (
          <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill,minmax(300px,1fr))", gap: 16 }}>
            {Array.from({length: 8}).map((_,i) => (
              <div key={i} className="skel" style={{ height: 140 }}/>
            ))}
          </div>
        ) : listings.length === 0 ? (
          <div style={{ textAlign: "center", padding: "100px 20px" }}>
            <div style={{ fontSize: 56, opacity: 0.1, marginBottom: 24, color: GOLD }}>◎</div>
            <h2 className="ph" style={{ fontSize: 32, fontWeight: 500, color: TX2, marginBottom: 16 }}>
              {tab === "offer" ? "Noch keine Angebote" : "Noch keine Gesuche"}
            </h2>
            <button onClick={() => setShowCreate(true)} className="btn-gold">Erstes Inserat erstellen</button>
          </div>
        ) : (
          <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill,minmax(320px,1fr))", gap: 16 }}>
            {listings.map((l, i) => {
              const card   = l.cards;
              const imgSrc = card?.image_url ? (card.image_url.includes(".") ? card.image_url : card.image_url + "/low.webp") : null;
              const isDeal = l.price && card?.price_market && l.price < card.price_market * 0.92;
              return (
                <div key={l.id} className={`listing-card fade-up${isDeal ? " deal" : ""}`} style={{ animationDelay: `${i * 30}ms` }}>
                  <div style={{ display: "flex", gap: 0 }}>
                    {/* Card image */}
                    <Link href={`/preischeck/${card?.id}`} style={{ textDecoration: "none", flexShrink: 0 }}>
                      <div style={{ width: 80, background: BG3, display: "flex", alignItems: "center", justifyContent: "center", padding: "10px 6px", alignSelf: "stretch" }}>
                        {imgSrc ? (
                          <img src={imgSrc} alt="" style={{ width: "100%", aspectRatio: "3/4", objectFit: "contain", borderRadius: 8 }}/>
                        ) : (
                          <div style={{ width: "100%", aspectRatio: "3/4", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 20, opacity: 0.15 }}>◎</div>
                        )}
                      </div>
                    </Link>

                    {/* Info */}
                    <div style={{ flex: 1, padding: "16px 18px", minWidth: 0 }}>
                      {isDeal && (
                        <div style={{ fontSize: 9, fontWeight: 700, color: GOLD, letterSpacing: "0.1em", marginBottom: 6 }}>
                          ✦ DEAL · UNTER MARKTWERT
                        </div>
                      )}
                      <Link href={`/preischeck/${card?.id}`} style={{ textDecoration: "none" }}>
                        <div style={{ fontSize: 14, fontWeight: 600, color: TX, marginBottom: 4, whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis" }}>
                          {card?.name_de || card?.name || "Karte"}
                        </div>
                      </Link>
                      <div style={{ fontSize: 10, color: "rgba(237,233,224,0.35)", textTransform: "uppercase", letterSpacing: "0.06em", marginBottom: 12 }}>
                        {card?.set_id} · #{card?.number} · {l.condition}
                      </div>
                      <div style={{ display: "flex", alignItems: "baseline", justifyContent: "space-between" }}>
                        <div className="ph" style={{ fontSize: 22, fontWeight: 500, color: GOLD }}>
                          {l.price ? l.price.toFixed(2) + " €" : "VHS"}
                        </div>
                        <div style={{ fontSize: 11, color: "rgba(237,233,224,0.35)" }}>
                          @{l.profiles?.username ?? "Anonym"}
                        </div>
                      </div>
                      {card?.price_market && l.price && (
                        <div style={{ fontSize: 10, color: "rgba(237,233,224,0.3)", marginTop: 4 }}>
                          Marktwert: {card.price_market.toFixed(2)} €
                          {isDeal && <span style={{ color: "#3db87a", marginLeft: 6 }}>↓ {((1 - l.price/card.price_market)*100).toFixed(0)}% günstiger</span>}
                        </div>
                      )}
                    </div>
                  </div>
                  {l.note && (
                    <div style={{ padding: "10px 18px", borderTop: "1px solid rgba(255,255,255,0.05)", fontSize: 12, color: TX2, fontStyle: "italic" }}>
                      „{l.note}"
                    </div>
                  )}
                </div>
              );
            })}
          </div>
        )}
      </div>

      {showCreate && (
        <CreateModal
          presellCardId={presellId}
          onClose={() => { setShowCreate(false); setPresellId(null); }}
          onCreated={() => { setShowCreate(false); setPresellId(null); loadListings(); }}
        />
      )}
    </div>
  );
}

function CreateModal({ presellCardId, onClose, onCreated }: {
  presellCardId: string|null; onClose: ()=>void; onCreated: ()=>void;
}) {
  const [search,    setSearch]    = useState("");
  const [results,   setResults]   = useState<any[]>([]);
  const [card,      setCard]      = useState<any>(null);
  const [type,      setType]      = useState<"offer"|"want">("offer");
  const [price,     setPrice]     = useState("");
  const [condition, setCondition] = useState("NM");
  const [note,      setNote]      = useState("");
  const [loading,   setLoading]   = useState(false);
  const [msg,       setMsg]       = useState("");

  useEffect(() => {
    if (!presellCardId) return;
    SB.from("cards").select("id,name,name_de,set_id,number,image_url,price_market")
      .eq("id", presellCardId).single()
      .then(({ data }) => { if (data) { setCard(data); setSearch(data.name_de || data.name); } });
  }, [presellCardId]);

  async function searchCards(q: string) {
    setSearch(q);
    if (q.length < 2) { setResults([]); return; }
    const res = await fetch(`/api/cards/search?q=${encodeURIComponent(q)}&limit=6`);
    const data = await res.json();
    setResults(data.cards ?? []);
  }

  async function submit() {
    if (!card) { setMsg("Bitte eine Karte wählen."); return; }
    setLoading(true);
    try {
      const { data: { session } } = await SB.auth.getSession();
      if (!session) { window.location.href = "/auth/login"; return; }

      // Direct Supabase insert (more reliable than API route)
      const { error } = await SB.from("marketplace_listings").insert({
        user_id:   session.user.id,
        seller_id: session.user.id,
        card_id:   card.id,
        type,
        price:     price ? parseFloat(price) : null,
        condition,
        note:      note.trim() || null,
        is_active: true,
      });

      if (error) { setMsg("Fehler: " + error.message); setLoading(false); return; }
      setMsg("✓ Inserat erstellt!");
      setTimeout(onCreated, 800);
    } catch (e: any) { setMsg("Fehler: " + e.message); }
    setLoading(false);
  }

  return (
    <div style={{ position: "fixed", inset: 0, background: "rgba(0,0,0,0.8)", display: "flex", alignItems: "center", justifyContent: "center", zIndex: 200, padding: 20 }}
      onClick={e => e.target === e.currentTarget && onClose()}>
      <div style={{ background: "#0F0F0F", borderRadius: 24, width: "100%", maxWidth: 520, padding: 36, position: "relative", border: "1px solid rgba(201,166,107,0.2)", maxHeight: "90vh", overflow: "auto" }}>
        <div style={{ position: "absolute", top: 0, left: "20%", right: "20%", height: 1, background: "linear-gradient(90deg,transparent,rgba(201,166,107,0.5),transparent)" }}/>
        <button onClick={onClose} style={{ position: "absolute", top: 16, right: 16, background: "none", border: "none", fontSize: 22, cursor: "pointer", color: TX2 }}>×</button>

        <div style={{ fontSize: 11, fontWeight: 600, letterSpacing: "0.16em", textTransform: "uppercase", color: GD2, marginBottom: 8 }}>Marktplatz</div>
        <h2 className="ph" style={{ fontSize: 32, fontWeight: 500, marginBottom: 28, color: TX }}>Inserat erstellen</h2>

        {/* Type toggle */}
        <div style={{ display: "flex", gap: 8, marginBottom: 24 }}>
          {(["offer","want"] as const).map(t => (
            <button key={t} onClick={() => setType(t)} style={{
              flex: 1, padding: "13px", borderRadius: 100, cursor: "pointer",
              background: type === t ? TX : "rgba(255,255,255,0.04)",
              color: type === t ? BG : TX2,
              border: `1px solid ${type === t ? TX : "rgba(255,255,255,0.1)"}`,
              fontSize: 14, fontWeight: 600, transition: "all 0.2s",
            }}>{t === "offer" ? "Anbieten" : "Suchen"}</button>
          ))}
        </div>

        {/* Card search */}
        <div style={{ marginBottom: 16, position: "relative" }}>
          <input value={search} onChange={e => searchCards(e.target.value)}
            placeholder="Karte suchen…"
            style={{ width: "100%", padding: "14px 18px", background: "rgba(255,255,255,0.04)", border: "1px solid rgba(255,255,255,0.1)", borderRadius: 12, color: TX, fontSize: 15, outline: "none", fontFamily: "inherit", transition: "border-color 0.2s" }}
            onFocus={e => (e.target as any).style.borderColor = "rgba(201,166,107,0.4)"}
            onBlur={e  => (e.target as any).style.borderColor = "rgba(255,255,255,0.1)"}/>
          {results.length > 0 && !card && (
            <div style={{ position: "absolute", top: "100%", left: 0, right: 0, zIndex: 10, background: "#111", border: "1px solid rgba(255,255,255,0.1)", borderRadius: "0 0 12px 12px", boxShadow: "0 16px 40px rgba(0,0,0,0.6)" }}>
              {results.map((r: any) => (
                <button key={r.id} onClick={() => { setCard(r); setSearch(r.name_de || r.name); setResults([]); }} style={{
                  display: "flex", alignItems: "center", gap: 10,
                  width: "100%", padding: "12px 16px", background: "none", border: "none",
                  cursor: "pointer", textAlign: "left", borderBottom: "1px solid rgba(255,255,255,0.06)",
                  transition: "background 0.1s",
                }}
                onMouseEnter={e => (e.currentTarget as any).style.background = "rgba(255,255,255,0.04)"}
                onMouseLeave={e => (e.currentTarget as any).style.background = "none"}>
                  <div style={{ fontSize: 13, fontWeight: 600, color: TX }}>{r.name_de || r.name}</div>
                  <div style={{ fontSize: 11, color: GD2, marginLeft: "auto", flexShrink: 0 }}>
                    {r.set_id} · #{r.number}{r.price_market ? ` · ${r.price_market.toFixed(2)} €` : ""}
                  </div>
                </button>
              ))}
            </div>
          )}
        </div>

        {/* Selected card */}
        {card && (
          <div style={{ display: "flex", gap: 12, padding: "12px 14px", background: "rgba(201,166,107,0.06)", borderRadius: 12, marginBottom: 20, alignItems: "center", border: "1px solid rgba(201,166,107,0.15)" }}>
            {card.image_url && (
              <img src={card.image_url.includes(".") ? card.image_url : card.image_url + "/low.webp"}
                alt="" style={{ width: 36, height: 50, objectFit: "contain", borderRadius: 4 }}/>
            )}
            <div style={{ flex: 1 }}>
              <div style={{ fontSize: 13, fontWeight: 600, color: TX }}>{card.name_de || card.name}</div>
              <div style={{ fontSize: 11, color: GD2 }}>{card.set_id} · #{card.number}{card.price_market ? ` · Marktwert: ${card.price_market.toFixed(2)} €` : ""}</div>
            </div>
            <button onClick={() => { setCard(null); setSearch(""); }} style={{ background: "none", border: "none", cursor: "pointer", color: TX2, fontSize: 18 }}>×</button>
          </div>
        )}

        {/* Price */}
        <div style={{ marginBottom: 16 }}>
          <label style={{ display: "block", fontSize: 11, fontWeight: 600, letterSpacing: "0.12em", textTransform: "uppercase", color: GD2, marginBottom: 8 }}>Preis (€)</label>
          <input type="number" step="0.50" min="0" value={price} onChange={e => setPrice(e.target.value)}
            placeholder={card?.price_market ? `Marktwert: ${card.price_market.toFixed(2)} €` : "0.00"}
            style={{ width: "100%", padding: "14px 18px", background: "rgba(255,255,255,0.04)", border: "1px solid rgba(255,255,255,0.1)", borderRadius: 12, color: TX, fontSize: 15, outline: "none", fontFamily: "inherit" }}/>
        </div>

        {/* Condition */}
        <div style={{ marginBottom: 16 }}>
          <label style={{ display: "block", fontSize: 11, fontWeight: 600, letterSpacing: "0.12em", textTransform: "uppercase", color: GD2, marginBottom: 8 }}>Zustand</label>
          <div style={{ display: "flex", gap: 6 }}>
            {["NM","LP","MP","HP","D"].map(c => (
              <button key={c} onClick={() => setCondition(c)} style={{
                flex: 1, padding: "10px 0", borderRadius: 100, fontSize: 12, fontWeight: 600, cursor: "pointer",
                border: "1px solid", transition: "all 0.15s",
                borderColor: condition === c ? "rgba(201,166,107,0.5)" : "rgba(255,255,255,0.1)",
                background: condition === c ? "rgba(201,166,107,0.12)" : "transparent",
                color: condition === c ? GOLD : TX2,
              }}>{c}</button>
            ))}
          </div>
        </div>

        {/* Note */}
        <div style={{ marginBottom: 24 }}>
          <label style={{ display: "block", fontSize: 11, fontWeight: 600, letterSpacing: "0.12em", textTransform: "uppercase", color: GD2, marginBottom: 8 }}>Notiz (optional)</label>
          <textarea value={note} onChange={e => setNote(e.target.value)} rows={2}
            placeholder="Zustand, Versand, etc."
            style={{ width: "100%", padding: "14px 18px", background: "rgba(255,255,255,0.04)", border: "1px solid rgba(255,255,255,0.1)", borderRadius: 12, color: TX, fontSize: 14, outline: "none", resize: "none", fontFamily: "inherit" }}/>
        </div>

        {msg && <div style={{ marginBottom: 16, fontSize: 13, color: msg.startsWith("✓") ? "#3db87a" : "#dc4a5a" }}>{msg}</div>}

        <button onClick={submit} disabled={loading || !card} className="btn-gold"
          style={{ width: "100%", justifyContent: "center", fontSize: 15, padding: "16px", opacity: loading || !card ? 0.5 : 1, borderRadius: 100 }}>
          {loading ? "Erstelle Inserat…" : "Inserat veröffentlichen ✦"}
        </button>
      </div>
    </div>
  );
}

files.page_portfolio.tsx:
"use client";
import { useState, useEffect } from "react";
import Link from "next/link";
import { createClient } from "@supabase/supabase-js";

const GOLD = "#C9A66B";
const BG   = "#0A0A0A";
const BG2  = "#111111";
const TX   = "#EDE9E0";
const TX2  = "rgba(237,233,224,0.7)";
const GD2  = "rgba(201,166,107,0.7)";

const SB = createClient(
  process.env.NEXT_PUBLIC_SUPABASE_URL!,
  process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!
);

interface Item {
  id: string; quantity: number; condition: string;
  buy_price: number | null; buy_date: string | null;
  cards: { id:string; name:string; name_de:string|null; set_id:string; number:string; image_url:string|null; price_market:number|null; price_avg7:number|null; };
}

function calcROI(item: Item) {
  const cur    = (item.cards?.price_market ?? 0) * item.quantity;
  const cost   = (item.buy_price ?? 0) * item.quantity;
  const profit = cur - cost;
  const roi    = cost > 0 ? (profit / cost) * 100 : null;
  return { cur, cost, profit, roi };
}

export default function PortfolioPage() {
  const [user,     setUser]     = useState<any>(null);
  const [col,      setCol]      = useState<Item[]>([]);
  const [wish,     setWish]     = useState<any[]>([]);
  const [tab,      setTab]      = useState<"sammlung"|"wishlist">("sammlung");
  const [loading,  setLoading]  = useState(true);
  const [editId,   setEditId]   = useState<string|null>(null);
  const [editVal,  setEditVal]  = useState("");

  useEffect(() => {
    async function load() {
      const { data: { user } } = await SB.auth.getUser();
      if (!user) { window.location.href = "/auth/login"; return; }
      setUser(user);
      const [{ data: cData }, { data: wData }] = await Promise.all([
        SB.from("user_collection")
          .select("id,quantity,condition,buy_price,buy_date,cards(id,name,name_de,set_id,number,image_url,price_market,price_avg7)")
          .eq("user_id", user.id).order("added_at", { ascending: false }).limit(200),
        SB.from("user_wishlist")
          .select("id,max_price,cards(id,name,name_de,set_id,number,image_url,price_market)")
          .eq("user_id", user.id).limit(100),
      ]);
      setCol((cData ?? []).map((c: any) => ({ ...c, cards: Array.isArray(c.cards) ? c.cards[0] : c.cards })));
      setWish((wData ?? []).map((w: any) => ({ ...w, cards: Array.isArray(w.cards) ? w.cards[0] : w.cards })));
      setLoading(false);
    }
    load();
  }, []);

  async function saveBuyPrice(itemId: string) {
    const price = parseFloat(editVal);
    if (!isNaN(price) && price >= 0) {
      try {
        await SB.from("user_collection").update({ buy_price: price }).eq("id", itemId);
        setCol(prev => prev.map(c => c.id === itemId ? { ...c, buy_price: price } : c));
      } catch {}
    }
    setEditId(null);
  }

  function exportCSV() {
    const rows = [
      ["Name","Set","Nr.","Zustand","Menge","Kaufpreis","Marktwert","Gewinn","ROI %"],
      ...col.map(c => {
        const { cur, cost, profit, roi } = calcROI(c);
        return [c.cards?.name_de||c.cards?.name||"", c.cards?.set_id||"", c.cards?.number||"", c.condition, c.quantity, cost>0?cost.toFixed(2):"", cur.toFixed(2), cost>0?profit.toFixed(2):"", roi!==null?roi.toFixed(1)+"%":""];
      })
    ];
    const csv = rows.map(r => r.map(v => `"${String(v).replace(/"/g,'""')}"`).join(",")).join("\n");
    const a = document.createElement("a");
    a.href = URL.createObjectURL(new Blob([csv], { type: "text/csv" }));
    a.download = "pokedax-portfolio.csv"; a.click();
  }

  const fmt = (n: number) => n.toLocaleString("de-DE", { minimumFractionDigits: 2, maximumFractionDigits: 2 });

  const totalValue  = col.reduce((s,c) => s + (c.cards?.price_market??0)*c.quantity, 0);
  const totalCost   = col.reduce((s,c) => s + (c.buy_price??0)*c.quantity, 0);
  const totalProfit = totalValue - totalCost;
  const totalROI    = totalCost > 0 ? (totalProfit/totalCost)*100 : null;
  const cardCount   = col.reduce((s,c) => s + c.quantity, 0);

  if (loading) return (
    <div style={{ background: BG, minHeight: "100vh", display: "flex", alignItems: "center", justifyContent: "center", color: GD2 }}>
      Lade Portfolio…
    </div>
  );

  return (
    <div style={{ background: BG, minHeight: "100vh", color: TX }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Playfair+Display:wght@400;500;700&display=swap');
        .ph { font-family:'Playfair Display',serif; letter-spacing:-0.05em; }
        .tab-btn { padding:10px 24px; border-radius:100px; border:1px solid transparent; font-size:14px; cursor:pointer; transition:all 0.2s; background:transparent; }
        .tab-btn.active { background:rgba(201,166,107,0.1); border-color:rgba(201,166,107,0.3); color:#C9A66B; font-weight:600; }
        .tab-btn:not(.active) { color:rgba(237,233,224,0.5); }
        .row-item { display:grid; grid-template-columns:52px 1fr 90px 110px 110px 100px 90px; gap:12px; padding:12px 16px; background:#111111; border-bottom:1px solid rgba(255,255,255,0.05); align-items:center; transition:background 0.15s; }
        .row-item:hover { background:#151515; }
        .row-item:last-child { border-bottom:none; }
        .edit-input { width:80px; padding:6px 10px; background:rgba(255,255,255,0.06); border:1px solid rgba(201,166,107,0.4); border-radius:100px; color:#EDE9E0; font-size:12px; outline:none; text-align:right; font-family:inherit; }
        .btn-gold { display:inline-flex; align-items:center; gap:6px; padding:10px 20px; background:#C9A66B; color:#0A0A0A; border-radius:100px; border:none; font-size:13px; font-weight:600; cursor:pointer; text-decoration:none; transition:transform 0.2s; }
        .btn-gold:hover { transform:scale(1.03); }
        .btn-outline { display:inline-flex; padding:10px 18px; border:1px solid rgba(201,166,107,0.3); color:#C9A66B; border-radius:100px; font-size:13px; text-decoration:none; background:transparent; cursor:pointer; transition:all 0.2s; }
        .btn-outline:hover { background:#C9A66B; color:#0A0A0A; }
        .card-grid { display:grid; grid-template-columns:repeat(auto-fill,minmax(180px,1fr)); gap:20px; }
        .wish-card { background:#111111; border:1px solid rgba(255,255,255,0.06); border-radius:20px; overflow:hidden; text-decoration:none; display:block; transition:transform 0.2s,border-color 0.2s; }
        .wish-card:hover { transform:translateY(-4px); border-color:rgba(201,166,107,0.25); }
        @keyframes skeleton { 0%,100%{opacity:.3} 50%{opacity:.6} }
        @media(max-width:900px){ .row-item{grid-template-columns:44px 1fr 80px 90px!important} .hide-mob{display:none!important} }
      `}</style>

      <div style={{ maxWidth: 1400, margin: "0 auto", padding: "clamp(60px,8vw,100px) clamp(20px,4vw,48px)" }}>

        {/* Header */}
        <div style={{ marginBottom: 48, display: "flex", justifyContent: "space-between", alignItems: "flex-end", flexWrap: "wrap", gap: 20 }}>
          <div>
            <div style={{ fontSize: 11, fontWeight: 600, letterSpacing: "0.16em", textTransform: "uppercase", color: GD2, marginBottom: 16 }}>Deine Sammlung</div>
            <h1 className="ph" style={{ fontSize: "clamp(36px,5vw,64px)", fontWeight: 500, color: TX, lineHeight: 1 }}>
              {user?.email?.split("@")[0]}'s<br/><span style={{ color: GOLD }}>Portfolio</span>
            </h1>
          </div>
          <div style={{ display: "flex", gap: 10 }}>
            <button onClick={exportCSV} className="btn-outline">↓ CSV</button>
            <Link href="/scanner" className="btn-gold">+ Karte scannen</Link>
          </div>
        </div>

        {/* Stats */}
        <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit,minmax(200px,1fr))", gap: 1, border: "1px solid rgba(201,166,107,0.15)", borderRadius: 20, overflow: "hidden", marginBottom: 48 }}>
          {[
            { l: "Sammlungswert", v: fmt(totalValue) + " €", highlight: true },
            { l: "Investiert", v: totalCost > 0 ? fmt(totalCost) + " €" : "–" },
            { l: "Gewinn / Verlust", v: totalCost > 0 ? (totalProfit >= 0 ? "+" : "") + fmt(totalProfit) + " €" : "–", color: totalCost > 0 ? (totalProfit >= 0 ? "#3db87a" : "#dc4a5a") : undefined },
            { l: "ROI", v: totalROI !== null ? (totalROI >= 0 ? "+" : "") + totalROI.toFixed(1) + "%" : "–", color: totalROI !== null ? (totalROI >= 0 ? "#3db87a" : "#dc4a5a") : undefined },
            { l: "Karten", v: cardCount.toString() },
          ].map(({ l, v, highlight, color }, i) => (
            <div key={l} style={{ padding: "clamp(20px,3vw,28px)", background: highlight ? TX : BG2, borderRight: i < 4 ? "1px solid rgba(201,166,107,0.1)" : undefined }}>
              <div style={{ fontSize: 10, fontWeight: 600, letterSpacing: "0.14em", textTransform: "uppercase", color: highlight ? "rgba(10,10,10,0.5)" : GD2, marginBottom: 10 }}>{l}</div>
              <div className="ph" style={{ fontSize: "clamp(22px,3vw,36px)", fontWeight: 500, letterSpacing: "-0.04em", color: highlight ? BG : (color ?? GOLD), lineHeight: 1 }}>{v}</div>
            </div>
          ))}
        </div>

        {/* Tabs */}
        <div style={{ display: "flex", gap: 8, marginBottom: 32 }}>
          {(["sammlung", "wishlist"] as const).map(t => (
            <button key={t} className={`tab-btn${tab===t?" active":""}`} onClick={() => setTab(t)}>
              {t === "sammlung" ? "Sammlung" : "Wunschliste"}
              <span style={{ marginLeft: 8, fontSize: 11, opacity: 0.5 }}>({t === "sammlung" ? col.length : wish.length})</span>
            </button>
          ))}
        </div>

        {/* Collection Table */}
        {tab === "sammlung" && (
          col.length === 0 ? (
            <div style={{ textAlign: "center", padding: "80px 20px" }}>
              <div style={{ fontSize: 48, opacity: 0.15, marginBottom: 20, color: GOLD }}>◎</div>
              <div style={{ fontSize: 18, color: TX2, marginBottom: 24 }}>Sammlung ist noch leer</div>
              <Link href="/scanner" className="btn-gold">Erste Karte scannen ✦</Link>
            </div>
          ) : (
            <div style={{ background: BG2, borderRadius: 20, overflow: "hidden", border: "1px solid rgba(255,255,255,0.06)" }}>
              {/* Table header */}
              <div className="row-item" style={{ background: "#0D0D0D", borderBottom: "1px solid rgba(201,166,107,0.1)" }}>
                {["", "Karte", "Zustand", "Kaufpreis", "Marktwert", "Gewinn", "ROI"].map((h,i) => (
                  <div key={i} className={`${i > 1 ? "hide-mob" : ""}`} style={{ fontSize: 10, fontWeight: 600, letterSpacing: "0.1em", textTransform: "uppercase", color: GD2, textAlign: i > 1 ? "right" : "left" }}>{h}</div>
                ))}
              </div>

              {col.map(item => {
                const card = item.cards;
                if (!card) return null;
                const { cur, cost, profit, roi } = calcROI(item);
                const hasCost = item.buy_price !== null && item.buy_price > 0;
                const imgSrc  = card.image_url ? (card.image_url.includes(".") ? card.image_url : card.image_url + "/low.webp") : null;
                return (
                  <div key={item.id} className="row-item">
                    <div style={{ width: 44, height: 60, borderRadius: 6, overflow: "hidden", background: "#1A1A1A", border: "1px solid rgba(255,255,255,0.06)", flexShrink: 0 }}>
                      {imgSrc && <img src={imgSrc} alt="" style={{ width: "100%", height: "100%", objectFit: "contain" }}/>}
                    </div>
                    <div style={{ minWidth: 0 }}>
                      <Link href={`/preischeck/${card.id}`} style={{ textDecoration: "none" }}>
                        <div style={{ fontSize: 13, fontWeight: 600, color: TX, whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis" }}>{card.name_de || card.name}</div>
                      </Link>
                      <div style={{ fontSize: 10, color: "rgba(237,233,224,0.3)", textTransform: "uppercase", letterSpacing: "0.06em", marginTop: 2 }}>
                        {card.set_id} · #{card.number}{item.quantity > 1 ? ` · ×${item.quantity}` : ""}
                      </div>
                    </div>
                    <div className="hide-mob" style={{ textAlign: "right", fontSize: 12, color: TX2 }}>{item.condition}</div>
                    {/* Buy price — editable */}
                    <div className="hide-mob" style={{ textAlign: "right" }}>
                      {editId === item.id ? (
                        <div style={{ display: "flex", gap: 4, justifyContent: "flex-end" }}>
                          <input className="edit-input" type="number" step="0.01" min="0" autoFocus
                            value={editVal} onChange={e => setEditVal(e.target.value)}
                            onKeyDown={e => { if (e.key === "Enter") saveBuyPrice(item.id); if (e.key === "Escape") setEditId(null); }}/>
                          <button onClick={() => saveBuyPrice(item.id)} style={{ padding: "4px 8px", background: GOLD, color: BG, border: "none", borderRadius: 100, cursor: "pointer", fontSize: 11 }}>✓</button>
                        </div>
                      ) : (
                        <button onClick={() => { setEditId(item.id); setEditVal(item.buy_price?.toString() ?? ""); }} style={{
                          background: "none", border: "none", cursor: "pointer",
                          fontFamily: "monospace", fontSize: 13,
                          color: hasCost ? TX : "rgba(237,233,224,0.25)",
                          textDecoration: hasCost ? "none" : "underline dotted",
                        }}>
                          {hasCost ? fmt(cost) + " €" : "Eintragen"}
                        </button>
                      )}
                    </div>
                    <div className="hide-mob" style={{ textAlign: "right", fontFamily: "monospace", fontSize: 13, color: GOLD }}>{cur > 0 ? fmt(cur) + " €" : "–"}</div>
                    <div className="hide-mob" style={{ textAlign: "right", fontFamily: "monospace", fontSize: 13, color: hasCost ? (profit >= 0 ? "#3db87a" : "#dc4a5a") : "rgba(237,233,224,0.25)" }}>
                      {hasCost ? (profit >= 0 ? "+" : "") + fmt(profit) + " €" : "–"}
                    </div>
                    <div className="hide-mob" style={{ textAlign: "right", fontSize: 13, fontWeight: 600, color: hasCost ? (roi! >= 0 ? "#3db87a" : "#dc4a5a") : "rgba(237,233,224,0.25)" }}>
                      {roi !== null ? (roi >= 0 ? "+" : "") + roi.toFixed(1) + "%" : "–"}
                    </div>
                  </div>
                );
              })}
            </div>
          )
        )}

        {/* Wishlist */}
        {tab === "wishlist" && (
          wish.length === 0 ? (
            <div style={{ textAlign: "center", padding: "80px 20px" }}>
              <div style={{ fontSize: 48, opacity: 0.15, marginBottom: 20, color: GOLD }}>◉</div>
              <div style={{ fontSize: 18, color: TX2, marginBottom: 24 }}>Wunschliste ist leer</div>
              <Link href="/preischeck" className="btn-gold">Karten entdecken</Link>
            </div>
          ) : (
            <div className="card-grid">
              {wish.map((w: any) => {
                const card = w.cards;
                if (!card) return null;
                const imgSrc = card.image_url?.includes(".") ? card.image_url : (card.image_url ? card.image_url + "/low.webp" : null);
                const isDeal = w.max_price && card.price_market && card.price_market <= w.max_price;
                return (
                  <Link key={w.id} href={`/preischeck/${card.id}`} className="wish-card">
                    <div style={{ aspectRatio: "3/4", background: "#1A1A1A", display: "flex", alignItems: "center", justifyContent: "center", overflow: "hidden", position: "relative" }}>
                      {imgSrc && <img src={imgSrc} alt={card.name} style={{ width: "85%", height: "85%", objectFit: "contain" }}/>}
                      {isDeal && <div style={{ position: "absolute", top: 10, right: 10, padding: "3px 8px", borderRadius: 100, background: "rgba(201,166,107,0.2)", color: GOLD, fontSize: 9, fontWeight: 700, border: "1px solid rgba(201,166,107,0.3)" }}>DEAL ✦</div>}
                    </div>
                    <div style={{ padding: "12px 14px 16px" }}>
                      <div style={{ fontSize: 12, fontWeight: 600, color: TX, marginBottom: 4, whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis" }}>{card.name_de || card.name}</div>
                      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "baseline" }}>
                        <div style={{ fontFamily: "monospace", fontSize: 14, fontWeight: 600, color: GOLD }}>{card.price_market?.toFixed(2)} €</div>
                        {w.max_price && <div style={{ fontSize: 10, color: "rgba(237,233,224,0.3)" }}>Limit: {w.max_price.toFixed(2)} €</div>}
                      </div>
                    </div>
                  </Link>
                );
              })}
            </div>
          )
        )}
      </div>
    </div>
  );
}

files.page_dashboard.tsx:
"use client";
import { useState, useEffect } from "react";
import Link from "next/link";
import { createClient } from "@supabase/supabase-js";

const GOLD = "#C9A66B";
const BG   = "#0A0A0A";
const BG2  = "#111111";
const BG3  = "#1A1A1A";
const TX   = "#EDE9E0";
const TX2  = "rgba(237,233,224,0.7)";
const GD2  = "rgba(201,166,107,0.7)";

const SB = createClient(
  process.env.NEXT_PUBLIC_SUPABASE_URL!,
  process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!
);

export default function DashboardPage() {
  const [user,      setUser]      = useState<any>(null);
  const [stats,     setStats]     = useState({ cards: 0, value: 0, scans: 0, listings: 0 });
  const [recentScans, setRecentScans] = useState<any[]>([]);
  const [topCards,  setTopCards]  = useState<any[]>([]);
  const [loading,   setLoading]   = useState(true);

  useEffect(() => {
    async function load() {
      const { data: { user } } = await SB.auth.getUser();
      if (!user) { window.location.href = "/auth/login"; return; }
      setUser(user);

      try {
        const [
          { data: collection },
          { data: scans },
          { data: listings },
        ] = await Promise.all([
          SB.from("user_collection")
            .select("quantity,buy_price,cards(price_market)")
            .eq("user_id", user.id).limit(200),
          SB.from("scan_logs")
            .select("id,created_at,cards(id,name,name_de,image_url,price_market)")
            .eq("user_id", user.id)
            .order("created_at", { ascending: false }).limit(5),
          SB.from("marketplace_listings")
            .select("id").eq("user_id", user.id).eq("is_active", true),
        ]);

        const col = collection ?? [];
        const totalValue = col.reduce((s: number, c: any) => {
          const card = Array.isArray(c.cards) ? c.cards[0] : c.cards;
          return s + (card?.price_market ?? 0) * (c.quantity ?? 1);
        }, 0);
        const cardCount = col.reduce((s: number, c: any) => s + (c.quantity ?? 1), 0);

        setStats({
          cards:    cardCount,
          value:    totalValue,
          scans:    (scans ?? []).length,
          listings: (listings ?? []).length,
        });

        const sc = (scans ?? []).map((s: any) => ({
          ...s, cards: Array.isArray(s.cards) ? s.cards[0] : s.cards,
        }));
        setRecentScans(sc);

        // Top cards by value
        const sorted = [...col]
          .map((c: any) => ({ ...c, cards: Array.isArray(c.cards) ? c.cards[0] : c.cards }))
          .filter((c: any) => c.cards?.price_market > 0)
          .sort((a: any, b: any) => (b.cards.price_market * b.quantity) - (a.cards.price_market * a.quantity))
          .slice(0, 6);
        setTopCards(sorted);
      } catch {}
      setLoading(false);
    }
    load();
  }, []);

  const username = user?.email?.split("@")[0] ?? "";
  const initial  = username[0]?.toUpperCase() ?? "U";

  if (loading) return (
    <div style={{ background: BG, minHeight: "100vh", display: "flex", alignItems: "center", justifyContent: "center", color: GD2 }}>
      Lade Dashboard…
    </div>
  );

  return (
    <div style={{ background: BG, minHeight: "100vh", color: TX }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Playfair+Display:wght@400;500;700&family=Instrument+Sans:wght@400;500;600&display=swap');
        .ph { font-family:'Playfair Display',serif; letter-spacing:-0.05em; }
        .stat-card { background:#111111; border:1px solid rgba(255,255,255,0.07); border-radius:20px; padding:clamp(20px,3vw,28px); transition:border-color 0.2s; text-decoration:none; display:block; }
        .stat-card:hover { border-color:rgba(201,166,107,0.25); }
        .quick-link { display:flex; align-items:center; gap:14px; padding:16px 20px; background:#111111; border:1px solid rgba(255,255,255,0.07); border-radius:16px; text-decoration:none; transition:all 0.2s; }
        .quick-link:hover { border-color:rgba(201,166,107,0.3); transform:translateX(4px); }
        .scan-row { display:flex; align-items:center; gap:12px; padding:14px 0; border-bottom:1px solid rgba(255,255,255,0.05); }
        .scan-row:last-child { border-bottom:none; }
        .top-card { background:#111111; border:1px solid rgba(255,255,255,0.06); border-radius:16px; overflow:hidden; text-decoration:none; display:block; transition:transform 0.2s,border-color 0.2s; }
        .top-card:hover { transform:translateY(-3px); border-color:rgba(201,166,107,0.2); }
        @keyframes fadeUp { from{opacity:0;transform:translateY(12px)} to{opacity:1;transform:translateY(0)} }
        .fade-up { animation:fadeUp 0.4s cubic-bezier(0.22,1,0.36,1) both; }
      `}</style>

      <div style={{ maxWidth: 1280, margin: "0 auto", padding: "clamp(60px,8vw,100px) clamp(20px,4vw,48px)" }}>

        {/* Header */}
        <div style={{ marginBottom: 56, display: "flex", alignItems: "center", gap: 20 }}>
          <div style={{ width: 64, height: 64, borderRadius: "50%", background: "rgba(201,166,107,0.15)", border: "2px solid rgba(201,166,107,0.3)", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 24, fontWeight: 700, color: GOLD, flexShrink: 0 }}>
            {initial}
          </div>
          <div>
            <div style={{ fontSize: 11, fontWeight: 600, letterSpacing: "0.16em", textTransform: "uppercase", color: GD2, marginBottom: 6 }}>Willkommen zurück</div>
            <h1 className="ph" style={{ fontSize: "clamp(32px,4vw,52px)", fontWeight: 500, color: TX, lineHeight: 1 }}>
              @{username}
            </h1>
          </div>
        </div>

        {/* Stats */}
        <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit,minmax(200px,1fr))", gap: 12, marginBottom: 48 }}>
          {[
            { href: "/dashboard/portfolio", icon: "◈", label: "Sammlungswert",  value: stats.value > 0 ? stats.value.toLocaleString("de-DE", { minimumFractionDigits: 2 }) + " €" : "–", sub: stats.cards + " Karten", highlight: true },
            { href: "/scanner",             icon: "⊙", label: "Letzte Scans",   value: stats.scans.toString(), sub: "Heute", highlight: false },
            { href: "/marketplace",         icon: "◎", label: "Aktive Inserate", value: stats.listings.toString(), sub: "Marktplatz", highlight: false },
            { href: "/dashboard/premium",   icon: "✦", label: "Premium",        value: "6,99 €", sub: "/ Monat", highlight: false, gold: true },
          ].map(({ href, icon, label, value, sub, highlight, gold }) => (
            <Link key={label} href={href} className="stat-card fade-up">
              <div style={{ fontSize: 20, color: gold ? GOLD : "rgba(201,166,107,0.4)", marginBottom: 16 }}>{icon}</div>
              <div style={{ fontSize: 10, fontWeight: 600, letterSpacing: "0.12em", textTransform: "uppercase", color: GD2, marginBottom: 8 }}>{label}</div>
              <div className="ph" style={{ fontSize: "clamp(24px,3vw,36px)", fontWeight: 500, color: highlight ? GOLD : TX, lineHeight: 1, marginBottom: 4 }}>{value}</div>
              <div style={{ fontSize: 12, color: "rgba(237,233,224,0.35)" }}>{sub}</div>
            </Link>
          ))}
        </div>

        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 24 }}>

          {/* Quick Links */}
          <div>
            <div style={{ fontSize: 11, fontWeight: 600, letterSpacing: "0.14em", textTransform: "uppercase", color: GD2, marginBottom: 16 }}>Quick Actions</div>
            <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
              {[
                { href: "/scanner",              icon: "⊙", label: "Karte scannen",       sub: "KI-gestützte Erkennung",     premium: true  },
                { href: "/dashboard/portfolio",  icon: "◈", label: "Portfolio ansehen",   sub: `${stats.cards} Karten · ${stats.value > 0 ? stats.value.toFixed(0) + " €" : "–"}`, premium: false },
                { href: "/preischeck",           icon: "◎", label: "Preischeck",           sub: "23.000+ Karten live",        premium: false },
                { href: "/marketplace",          icon: "⇄", label: "Marktplatz",           sub: "Kaufen & Verkaufen",         premium: false },
                { href: "/dashboard/wishlist",   icon: "◉", label: "Wunschliste",          sub: "Automatisches Matching",     premium: true  },
                { href: "/forum",                icon: "◉", label: "Community Forum",      sub: "Diskussionen & Tipps",       premium: false },
              ].map(({ href, icon, label, sub, premium }) => (
                <Link key={href} href={href} className="quick-link">
                  <div style={{ width: 36, height: 36, borderRadius: "50%", background: premium ? "rgba(201,166,107,0.12)" : "rgba(255,255,255,0.05)", border: `1px solid ${premium ? "rgba(201,166,107,0.25)" : "rgba(255,255,255,0.08)"}`, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 14, color: premium ? GOLD : "rgba(201,166,107,0.4)", flexShrink: 0 }}>
                    {premium ? "✦" : icon}
                  </div>
                  <div style={{ flex: 1, minWidth: 0 }}>
                    <div style={{ fontSize: 14, fontWeight: 600, color: TX, marginBottom: 2 }}>{label}</div>
                    <div style={{ fontSize: 11, color: "rgba(237,233,224,0.4)", whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis" }}>{sub}</div>
                  </div>
                  {premium && <span style={{ fontSize: 9, fontWeight: 700, color: "rgba(201,166,107,0.6)", background: "rgba(201,166,107,0.08)", padding: "2px 8px", borderRadius: 4, flexShrink: 0 }}>PRO</span>}
                  <span style={{ color: "rgba(237,233,224,0.2)", fontSize: 16 }}>→</span>
                </Link>
              ))}
            </div>
          </div>

          {/* Right column */}
          <div style={{ display: "flex", flexDirection: "column", gap: 24 }}>

            {/* Recent scans */}
            {recentScans.length > 0 && (
              <div>
                <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 16 }}>
                  <div style={{ fontSize: 11, fontWeight: 600, letterSpacing: "0.14em", textTransform: "uppercase", color: GD2 }}>Letzte Scans</div>
                  <Link href="/scanner" style={{ fontSize: 12, color: GOLD, textDecoration: "none" }}>Scanner →</Link>
                </div>
                <div style={{ background: BG2, borderRadius: 16, padding: "8px 16px", border: "1px solid rgba(255,255,255,0.07)" }}>
                  {recentScans.map(s => {
                    const card = s.cards;
                    if (!card) return null;
                    const img = card.image_url ? (card.image_url.includes(".") ? card.image_url : card.image_url + "/low.webp") : null;
                    return (
                      <Link key={s.id} href={`/preischeck/${card.id}`} style={{ textDecoration: "none" }}>
                        <div className="scan-row">
                          <div style={{ width: 36, height: 50, borderRadius: 5, overflow: "hidden", background: BG3, flexShrink: 0 }}>
                            {img && <img src={img} alt="" style={{ width: "100%", height: "100%", objectFit: "contain" }}/>}
                          </div>
                          <div style={{ flex: 1, minWidth: 0 }}>
                            <div style={{ fontSize: 13, fontWeight: 600, color: TX, whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis" }}>{card.name_de || card.name}</div>
                            <div style={{ fontSize: 11, color: "rgba(237,233,224,0.35)" }}>{new Date(s.created_at).toLocaleDateString("de-DE")}</div>
                          </div>
                          {card.price_market && (
                            <div style={{ fontFamily: "monospace", fontSize: 13, fontWeight: 600, color: GOLD, flexShrink: 0 }}>
                              {card.price_market.toFixed(2)} €
                            </div>
                          )}
                        </div>
                      </Link>
                    );
                  })}
                </div>
              </div>
            )}

            {/* Top cards */}
            {topCards.length > 0 && (
              <div>
                <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 16 }}>
                  <div style={{ fontSize: 11, fontWeight: 600, letterSpacing: "0.14em", textTransform: "uppercase", color: GD2 }}>Wertvollste Karten</div>
                  <Link href="/dashboard/portfolio" style={{ fontSize: 12, color: GOLD, textDecoration: "none" }}>Portfolio →</Link>
                </div>
                <div style={{ display: "grid", gridTemplateColumns: "repeat(3,1fr)", gap: 8 }}>
                  {topCards.slice(0,6).map((item: any) => {
                    const card = item.cards;
                    const img  = card?.image_url ? (card.image_url.includes(".") ? card.image_url : card.image_url + "/low.webp") : null;
                    return (
                      <Link key={item.id} href={`/preischeck/${card?.id}`} className="top-card">
                        <div style={{ aspectRatio: "3/4", background: BG3, display: "flex", alignItems: "center", justifyContent: "center", overflow: "hidden" }}>
                          {img && <img src={img} alt="" style={{ width: "90%", height: "90%", objectFit: "contain" }} loading="lazy"/>}
                        </div>
                        <div style={{ padding: "8px 10px" }}>
                          <div style={{ fontSize: 10, fontWeight: 600, color: TX, whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis" }}>{card?.name_de || card?.name}</div>
                          <div style={{ fontFamily: "monospace", fontSize: 12, fontWeight: 600, color: GOLD }}>{card?.price_market?.toFixed(2)} €</div>
                        </div>
                      </Link>
                    );
                  })}
                </div>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}

