"use client";
import { useState } from "react";
import Link from "next/link";
import { createClient } from "@supabase/supabase-js";

const GOLD = "#C9A66B";
const BG   = "#0A0A0A";
const BG2  = "#111111";
const TX   = "#EDE9E0";
const TX2  = "rgba(237,233,224,0.7)";
const GD2  = "rgba(201,166,107,0.7)";

const SB = createClient(
  process.env.NEXT_PUBLIC_SUPABASE_URL!,
  process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!
);

const FEATURES = [
  { icon: "⊙", title: "Unlimitierter KI-Scanner",   desc: "Scanne so viele Karten wie du willst. Free: 5/Tag.",     premium: true  },
  { icon: "◈", title: "Portfolio ROI-Tracking",      desc: "Gewinn/Verlust und ROI pro Karte in Echtzeit.",          premium: true  },
  { icon: "◉", title: "Wishlist-Alerts per E-Mail",  desc: "Sofort benachrichtigt wenn deine Wunschkarte verfügbar.", premium: true  },
  { icon: "⇄", title: "3 % statt 5 % Provision",    desc: "Spare bei jedem Verkauf auf dem Marktplatz.",             premium: true  },
  { icon: "▲", title: "Preisalarme",                 desc: "Alert wenn eine Karte deinen Zielpreis erreicht.",        premium: true  },
  { icon: "◎", title: "Preistrends & Insights",      desc: "Top Gewinner/Verlierer der Woche. Advanced Charts.",      premium: true  },
  { icon: "◫", title: "Preischeck",                  desc: "23.000+ Karten mit Live-Preisen.",                       premium: false },
  { icon: "◇", title: "Marktplatz",                  desc: "Kaufen & Verkaufen via Escrow.",                         premium: false },
  { icon: "◉", title: "Community Forum",             desc: "Diskussionen, Tipps und Trades.",                        premium: false },
  { icon: "◈", title: "Basis-Portfolio",             desc: "Sammlung verwalten und Wert berechnen.",                 premium: false },
];

export default function PremiumPage() {
  const [loading, setLoading] = useState(false);
  const [annual,  setAnnual]  = useState(false);

  async function checkout() {
    setLoading(true);
    try {
      const { data: { session } } = await SB.auth.getSession();
      if (!session) { window.location.href = "/auth/login"; return; }
      const res = await fetch("/api/stripe/checkout", {
        method: "POST",
        headers: { "Content-Type": "application/json", "Authorization": `Bearer ${session.access_token}` },
        body: JSON.stringify({ plan: annual ? "annual" : "monthly" }),
      });
      const { url } = await res.json();
      if (url) window.location.href = url;
    } catch {}
    setLoading(false);
  }

  return (
    <div style={{ background: BG, minHeight: "100vh", color: TX }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Playfair+Display:wght@400;500;700&family=Instrument+Sans:wght@400;500;600&display=swap');
        .ph { font-family:'Playfair Display',serif; letter-spacing:-0.05em; }
        .feat-row { display:flex; gap:14px; align-items:flex-start; padding:16px 0; border-bottom:1px solid rgba(255,255,255,0.05); }
        .feat-row:last-child { border-bottom:none; }
        .btn-gold { display:inline-flex; align-items:center; gap:8px; padding:18px 40px; background:#C9A66B; color:#0A0A0A; border-radius:100px; border:none; font-size:16px; font-weight:700; cursor:pointer; transition:transform 0.2s,box-shadow 0.2s; width:100%; justify-content:center; }
        .btn-gold:hover { transform:scale(1.02); box-shadow:0 12px 40px rgba(201,166,107,0.35); }
        .btn-gold:disabled { opacity:0.6; cursor:not-allowed; transform:none; }
        .toggle-bg { background:rgba(255,255,255,0.06); border-radius:100px; padding:4px; display:inline-flex; cursor:pointer; }
        .toggle-opt { padding:8px 20px; border-radius:100px; font-size:13px; font-weight:500; transition:all 0.2s; }
        .toggle-opt.active { background:#C9A66B; color:#0A0A0A; font-weight:700; }
        .toggle-opt:not(.active) { color:rgba(237,233,224,0.5); }
        @keyframes fadeUp { from{opacity:0;transform:translateY(20px)} to{opacity:1;transform:translateY(0)} }
        .fade-up { animation:fadeUp 0.6s cubic-bezier(0.22,1,0.36,1) both; }
      `}</style>

      {/* Hero */}
      <div style={{ textAlign: "center", padding: "clamp(80px,12vw,140px) clamp(20px,4vw,48px) clamp(60px,8vw,100px)", position: "relative", overflow: "hidden" }}>
        {/* Background glow */}
        <div style={{ position: "absolute", top: "20%", left: "50%", transform: "translateX(-50%)", width: 600, height: 300, background: "radial-gradient(ellipse,rgba(201,166,107,0.08),transparent 70%)", pointerEvents: "none" }}/>

        <div style={{ display: "inline-flex", alignItems: "center", gap: 8, padding: "6px 20px", background: "rgba(201,166,107,0.1)", border: "1px solid rgba(201,166,107,0.25)", borderRadius: 100, fontSize: 12, fontWeight: 600, color: GOLD, marginBottom: 24, letterSpacing: "0.1em", textTransform: "uppercase" }}>
          ✦ Premium Plan
        </div>

        <h1 className="ph fade-up" style={{ fontSize: "clamp(48px,7vw,96px)", fontWeight: 500, color: TX, lineHeight: 1, marginBottom: 24 }}>
          Für ernsthafte<br/>Sammler.
        </h1>

        <p style={{ fontSize: "clamp(16px,1.8vw,20px)", color: TX2, maxWidth: 480, margin: "0 auto 48px", lineHeight: 1.8 }}>
          Unlimitierter Scanner. Portfolio ROI. Preisalarme.<br/>
          Alles was du brauchst um deine Sammlung zu maximieren.
        </p>

        {/* Billing toggle */}
        <div style={{ marginBottom: 48 }}>
          <div className="toggle-bg" onClick={() => setAnnual(!annual)}>
            <div className={`toggle-opt${!annual ? " active" : ""}`}>Monatlich</div>
            <div className={`toggle-opt${annual ? " active" : ""}`}>
              Jährlich <span style={{ fontSize: 10, marginLeft: 4, background: "#3db87a", color: "white", padding: "1px 6px", borderRadius: 4 }}>-20%</span>
            </div>
          </div>
        </div>

        {/* Price card */}
        <div style={{ maxWidth: 420, margin: "0 auto", background: BG2, borderRadius: 32, padding: "40px 36px", border: "1px solid rgba(201,166,107,0.25)", position: "relative", overflow: "hidden", boxShadow: "0 40px 80px rgba(0,0,0,0.5)" }}>
          <div style={{ position: "absolute", top: 0, left: "15%", right: "15%", height: 1, background: "linear-gradient(90deg,transparent,rgba(201,166,107,0.5),transparent)" }}/>

          <div className="ph" style={{ fontSize: 72, fontWeight: 500, color: GOLD, lineHeight: 1, marginBottom: 4 }}>
            {annual ? "5,59" : "6,99"}
          </div>
          <div style={{ fontSize: 14, color: TX2, marginBottom: 8 }}>€ / Monat{annual ? " · Jährlich abgerechnet" : ""}</div>
          {annual && <div style={{ fontSize: 12, color: "#3db87a", marginBottom: 24 }}>Du sparst 16,80 € / Jahr</div>}

          <button onClick={checkout} disabled={loading} className="btn-gold" style={{ marginBottom: 16 }}>
            {loading ? "Weiterleitung…" : "Premium werden ✦"}
          </button>
          <div style={{ fontSize: 12, color: "rgba(237,233,224,0.35)", textAlign: "center" }}>
            Jederzeit kündbar · Keine versteckten Kosten
          </div>
        </div>
      </div>

      {/* Feature comparison */}
      <div style={{ maxWidth: 800, margin: "0 auto", padding: "0 clamp(20px,4vw,48px) clamp(80px,10vw,140px)" }}>
        <div style={{ width: "100%", height: 1, background: "linear-gradient(90deg,transparent,rgba(201,166,107,0.2),transparent)", marginBottom: 64 }}/>

        <h2 className="ph" style={{ fontSize: "clamp(28px,4vw,48px)", fontWeight: 500, textAlign: "center", marginBottom: 8 }}>Was du bekommst</h2>
        <p style={{ textAlign: "center", color: TX2, fontSize: 15, marginBottom: 48 }}>Premium Features sind mit ✦ markiert.</p>

        <div style={{ background: BG2, borderRadius: 24, overflow: "hidden", border: "1px solid rgba(201,166,107,0.15)" }}>
          <div style={{ display: "grid", gridTemplateColumns: "1fr auto auto", padding: "12px 24px", background: "rgba(201,166,107,0.05)", borderBottom: "1px solid rgba(255,255,255,0.06)", fontSize: 10, fontWeight: 700, letterSpacing: "0.12em", textTransform: "uppercase", color: GD2 }}>
            <div>Feature</div>
            <div style={{ textAlign: "center", width: 80 }}>Free</div>
            <div style={{ textAlign: "center", width: 80, color: GOLD }}>Premium</div>
          </div>
          {FEATURES.map(({ icon, title, desc, premium }) => (
            <div key={title} className="feat-row" style={{ padding: "0 24px", alignItems: "center" }}>
              <div style={{ flex: 1, display: "flex", gap: 12, alignItems: "center", padding: "14px 0" }}>
                <span style={{ fontSize: 16, color: premium ? GOLD : "rgba(201,166,107,0.3)", width: 20, flexShrink: 0 }}>{icon}</span>
                <div>
                  <div style={{ fontSize: 14, fontWeight: 600, color: TX, marginBottom: 2 }}>{title}</div>
                  <div style={{ fontSize: 12, color: "rgba(237,233,224,0.4)" }}>{desc}</div>
                </div>
              </div>
              <div style={{ textAlign: "center", width: 80, fontSize: 16, color: premium ? "rgba(237,233,224,0.2)" : "#3db87a" }}>
                {premium ? "–" : "✓"}
              </div>
              <div style={{ textAlign: "center", width: 80, fontSize: 16, color: "#3db87a" }}>✓</div>
            </div>
          ))}
        </div>

        {/* FAQ */}
        <div style={{ marginTop: 64 }}>
          <h2 className="ph" style={{ fontSize: 32, fontWeight: 500, textAlign: "center", marginBottom: 40 }}>Häufige Fragen</h2>
          <div style={{ display: "flex", flexDirection: "column", gap: 1 }}>
            {[
              { q: "Kann ich jederzeit kündigen?", a: "Ja, jederzeit. Nach der Kündigung behältst du Premium bis zum Ende des Abrechnungszeitraums." },
              { q: "Welche Zahlungsmethoden gibt es?", a: "Kreditkarte, PayPal und SEPA-Lastschrift via Stripe. Sicher und verschlüsselt." },
              { q: "Gibt es eine Testphase?", a: "Kostenlose Nutzung mit 5 Scans/Tag. Premium schaltet alles frei." },
              { q: "Wie funktioniert das Escrow?", a: "Dein Geld wird von pokédax treuhänderisch gehalten und erst freigegeben wenn du den Kartenerhalt bestätigst." },
            ].map(({ q, a }) => (
              <div key={q} style={{ background: BG2, border: "1px solid rgba(255,255,255,0.06)", borderRadius: 12, padding: "20px 24px" }}>
                <div style={{ fontSize: 15, fontWeight: 600, color: TX, marginBottom: 8 }}>{q}</div>
                <div style={{ fontSize: 14, color: TX2, lineHeight: 1.7 }}>{a}</div>
              </div>
            ))}
          </div>
        </div>

        {/* Bottom CTA */}
        <div style={{ marginTop: 64, textAlign: "center" }}>
          <button onClick={checkout} disabled={loading} className="btn-gold" style={{ maxWidth: 400 }}>
            {loading ? "Weiterleitung…" : "Jetzt Premium werden ✦"}
          </button>
          <div style={{ marginTop: 12, fontSize: 13, color: "rgba(237,233,224,0.3)" }}>
            {annual ? "5,59 € / Monat · 67,08 € / Jahr" : "6,99 € / Monat"} · Jederzeit kündbar
          </div>
        </div>
      </div>
    </div>
  );
}

files.page_sets.tsx:
"use client";
import { useState, useEffect } from "react";
import Link from "next/link";
import { createClient } from "@supabase/supabase-js";

const SB = createClient(process.env.NEXT_PUBLIC_SUPABASE_URL!, process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!);

export default function SetsPage() {
  const [sets,    setSets]    = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [query,   setQuery]   = useState("");

  useEffect(() => {
    SB.from("sets")
      .select("id,name,name_de,series,card_count,release_date")
      .order("release_date", { ascending: false }).limit(300)
      .then(({ data }) => { setSets(data ?? []); setLoading(false); });
  }, []);

  const grouped = sets
    .filter(s => !query || (s.name_de||s.name||"").toLowerCase().includes(query.toLowerCase()) || s.id.toLowerCase().includes(query.toLowerCase()))
    .reduce((acc: Record<string, any[]>, s: any) => {
      const series = s.series || "Sonstige";
      if (!acc[series]) acc[series] = [];
      acc[series].push(s);
      return acc;
    }, {});

  function getSetImage(set: any) {
    if (set.logo_url) return set.logo_url;
    if (set.image_url) return set.image_url;
    // TCGdex fallback
    return `https://assets.tcgdex.net/en/${set.id}/logo.png`;
  }

  return (
    <div style={{ background:"#0A0A0A", minHeight:"100vh", color:"#EDE9E0" }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Playfair+Display:wght@400;500;700&display=swap');
        .ph { font-family:'Playfair Display',serif; letter-spacing:-0.05em; }
        .set-card { background:#111111; border:1px solid rgba(255,255,255,0.07); border-radius:20px; overflow:hidden; text-decoration:none; display:block; transition:border-color 0.2s,transform 0.2s; }
        .set-card:hover { border-color:rgba(201,166,107,0.35); transform:translateY(-3px); }
        .search-input { width:100%; max-width:480px; padding:14px 20px 14px 48px; background:rgba(255,255,255,0.04); border:1px solid rgba(255,255,255,0.1); border-radius:100px; color:#EDE9E0; font-size:15px; outline:none; font-family:inherit; transition:border-color 0.2s; }
        .search-input:focus { border-color:rgba(201,166,107,0.4); }
        .search-input::placeholder { color:rgba(237,233,224,0.3); }
        @keyframes skeleton { 0%,100%{opacity:.3} 50%{opacity:.6} }
      `}</style>

      <div style={{ maxWidth:1600, margin:"0 auto", padding:"clamp(60px,8vw,100px) clamp(20px,4vw,48px)" }}>

        <div style={{ marginBottom:56 }}>
          <div style={{ fontSize:11, fontWeight:600, letterSpacing:"0.16em", textTransform:"uppercase", color:"rgba(201,166,107,0.7)", marginBottom:16 }}>Datenbank</div>
          <h1 className="ph" style={{ fontSize:"clamp(40px,6vw,80px)", fontWeight:500, color:"#EDE9E0", lineHeight:1, marginBottom:24 }}>
            {loading ? "…" : sets.length} Sets &<br/><span style={{ color:"#C9A66B" }}>Serien</span>
          </h1>
          <div style={{ position:"relative", display:"inline-block" }}>
            <span style={{ position:"absolute", left:18, top:"50%", transform:"translateY(-50%)", fontSize:16, color:"rgba(237,233,224,0.25)" }}>◎</span>
            <input className="search-input" placeholder="Set suchen…" value={query} onChange={e => setQuery(e.target.value)}/>
          </div>
        </div>

        {loading ? (
          <div style={{ display:"grid", gridTemplateColumns:"repeat(auto-fill,minmax(240px,1fr))", gap:12 }}>
            {Array.from({length:12}).map((_,i) => (
              <div key={i} style={{ height:120, background:"#111", borderRadius:20, opacity:0.4, animation:"skeleton 1.5s ease-in-out infinite" }}/>
            ))}
          </div>
        ) : (
          Object.entries(grouped).map(([series, seriesSets]) => (
            <div key={series} style={{ marginBottom:56 }}>
              <div style={{ display:"flex", alignItems:"center", gap:16, marginBottom:20 }}>
                <div style={{ fontSize:11, fontWeight:600, letterSpacing:"0.14em", textTransform:"uppercase", color:"rgba(201,166,107,0.7)" }}>{series}</div>
                <div style={{ flex:1, height:1, background:"linear-gradient(90deg,rgba(201,166,107,0.2),transparent)" }}/>
                <div style={{ fontSize:11, color:"rgba(237,233,224,0.3)" }}>{seriesSets.length} Sets</div>
              </div>
              <div style={{ display:"grid", gridTemplateColumns:"repeat(auto-fill,minmax(240px,1fr))", gap:10 }}>
                {seriesSets.map((set: any) => {
                  const imgSrc = "https://assets.tcgdex.net/en/" + set.id + "/logo.png";
                  return (
                    <Link key={set.id} href={`/sets/${set.id}`} className="set-card">
                      {/* Set logo/image */}
                      <div style={{ background:"#1A1A1A", padding:"20px 24px", display:"flex", alignItems:"center", justifyContent:"center", minHeight:80 }}>
                        <img
                          src={imgSrc}
                          alt={set.name_de || set.name}
                          style={{ maxHeight:50, maxWidth:"100%", objectFit:"contain" }}
                          onError={(e) => {
                            const t = e.target as HTMLImageElement;
                            t.style.display = "none";
                            const parent = t.parentElement;
                            if (parent) {
                              parent.innerHTML = `<div style="font-size:9px;font-weight:700;letter-spacing:0.12em;text-transform:uppercase;color:#C9A66B;opacity:0.6">${set.id.toUpperCase()}</div>`;
                            }
                          }}
                        />
                      </div>
                      <div style={{ padding:"14px 18px 16px", borderTop:"1px solid rgba(255,255,255,0.05)" }}>
                        <div style={{ fontSize:14, fontWeight:600, color:"#EDE9E0", marginBottom:4, lineHeight:1.3 }}>
                          {set.name_de || set.name}
                        </div>
                        <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center" }}>
                          {set.card_count && <div style={{ fontSize:11, color:"rgba(237,233,224,0.4)" }}>{set.card_count} Karten</div>}
                          {set.release_date && <div style={{ fontSize:10, color:"rgba(201,166,107,0.5)" }}>{new Date(set.release_date).getFullYear()}</div>}
                        </div>
                      </div>
                    </Link>
                  );
                })}
              </div>
            </div>
          ))
        )}
      </div>
    </div>
  );
}

files.set_detail_page.tsx:
"use client";
import { useState, useEffect } from "react";
import { useParams } from "next/navigation";
import Link from "next/link";
import { createClient } from "@supabase/supabase-js";

const GOLD = "#C9A66B";
const BG   = "#0A0A0A";
const BG2  = "#111111";
const BG3  = "#1A1A1A";
const TX   = "#EDE9E0";
const TX2  = "rgba(237,233,224,0.7)";
const GD2  = "rgba(201,166,107,0.7)";

const SB = createClient(
  process.env.NEXT_PUBLIC_SUPABASE_URL!,
  process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!
);

export default function SetDetailPage() {
  const { id } = useParams();
  const [cards,   setCards]   = useState<any[]>([]);
  const [setInfo, setSetInfo] = useState<any>(null);
  const [loading, setLoading] = useState(true);
  const [sort,    setSort]    = useState<"number"|"price_desc"|"price_asc">("number");
  const [query,   setQuery]   = useState("");

  useEffect(() => {
    if (!id) return;
    loadSet();
  }, [id, sort]);

  async function loadSet() {
    setLoading(true);
    const [{ data: setData }, { data: cardsData }] = await Promise.all([
      SB.from("sets").select("id,name,name_de,series,card_count,release_date").eq("id", id as string).single(),
      SB.from("cards").select("id,name,name_de,number,image_url,price_market,price_avg7,rarity,types,is_holo").eq("set_id", id as string).limit(500),
    ]);
    if (setData) setSetInfo(setData);
    let sorted = cardsData || [];
    if (sort === "number") sorted = [...sorted].sort((a,b) => (parseInt(a.number)||0) - (parseInt(b.number)||0));
    else if (sort === "price_desc") sorted = [...sorted].sort((a,b) => (b.price_market||0) - (a.price_market||0));
    else sorted = [...sorted].sort((a,b) => (a.price_market||0) - (b.price_market||0));
    setCards(sorted);
    setLoading(false);
  }

  const filtered = query ? cards.filter(c => (c.name_de||c.name).toLowerCase().includes(query.toLowerCase()) || c.number.includes(query)) : cards;

  return (
    <div style={{ background: BG, minHeight: "100vh", color: TX }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Playfair+Display:wght@400;500;700&display=swap');
        .ph { font-family:'Playfair Display',serif; letter-spacing:-0.05em; }
        .card-tile { background:#111111; border:1px solid rgba(255,255,255,0.06); border-radius:20px; overflow:hidden; text-decoration:none; display:block; transition:transform 0.25s cubic-bezier(0.22,1,0.36,1),border-color 0.2s,box-shadow 0.25s; }
        .card-tile:hover { transform:translateY(-6px) scale(1.02); border-color:rgba(201,166,107,0.3); box-shadow:0 20px 50px rgba(0,0,0,0.5); }
        .sort-btn { padding:9px 18px; border-radius:100px; border:1px solid transparent; font-size:12px; cursor:pointer; transition:all 0.15s; background:transparent; }
        .sort-btn.active { background:rgba(201,166,107,0.1); border-color:rgba(201,166,107,0.3); color:#C9A66B; font-weight:600; }
        .sort-btn:not(.active) { color:rgba(237,233,224,0.5); }
        @keyframes skeleton { 0%,100%{opacity:.3} 50%{opacity:.6} }
        .skel { animation:skeleton 1.5s ease-in-out infinite; border-radius:20px; background:#111; }
      `}</style>

      <div style={{ maxWidth: 1600, margin: "0 auto", padding: "clamp(60px,8vw,100px) clamp(20px,4vw,48px)" }}>

        {/* Breadcrumb */}
        <div style={{ marginBottom: 40, display: "flex", gap: 8, alignItems: "center", fontSize: 13, color: "rgba(237,233,224,0.4)" }}>
          <Link href="/sets" style={{ color: "rgba(237,233,224,0.4)", textDecoration: "none" }}>← Alle Sets</Link>
        </div>

        {/* Header */}
        <div style={{ marginBottom: 48, display: "flex", justifyContent: "space-between", alignItems: "flex-end", flexWrap: "wrap", gap: 20 }}>
          <div>
            <div style={{ fontSize: 11, fontWeight: 600, letterSpacing: "0.16em", textTransform: "uppercase", color: GD2, marginBottom: 12 }}>
              {setInfo?.series || "Set"} · {(id as string)?.toUpperCase()}
            </div>
            <h1 className="ph" style={{ fontSize: "clamp(36px,5vw,72px)", fontWeight: 500, color: TX, lineHeight: 1 }}>
              {setInfo?.name_de || setInfo?.name || id}
            </h1>
            {!loading && (
              <div style={{ fontSize: 14, color: TX2, marginTop: 10 }}>
                {filtered.length} Karten{setInfo?.card_count ? ` von ${setInfo.card_count}` : ""}
              </div>
            )}
          </div>
          <div style={{ display: "flex", gap: 8, flexWrap: "wrap", alignItems: "center" }}>
            {/* Filter */}
            <input value={query} onChange={e => setQuery(e.target.value)} placeholder="Karte filtern…"
              style={{ padding: "10px 18px", background: "rgba(255,255,255,0.04)", border: "1px solid rgba(255,255,255,0.1)", borderRadius: 100, color: TX, fontSize: 13, outline: "none", fontFamily: "inherit", width: 180 }}/>
            {/* Sort */}
            {(["number","price_desc","price_asc"] as const).map(v => (
              <button key={v} className={`sort-btn${sort===v?" active":""}`} onClick={() => setSort(v)}>
                {v==="number"?"Nr. ↑":v==="price_desc"?"Preis ↓":"Preis ↑"}
              </button>
            ))}
          </div>
        </div>

        {/* Grid */}
        <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill,minmax(190px,1fr))", gap: 18 }}>
          {loading ? (
            Array.from({ length: 20 }).map((_,i) => (
              <div key={i} className="skel" style={{ aspectRatio: "3/5" }}/>
            ))
          ) : filtered.length === 0 ? (
            <div style={{ gridColumn: "1/-1", textAlign: "center", padding: "60px 0", color: TX2 }}>Keine Karten gefunden</div>
          ) : (
            filtered.map(card => {
              const imgSrc = card.image_url ? (card.image_url.includes(".") ? card.image_url : card.image_url + "/low.webp") : null;
              return (
                <Link key={card.id} href={`/preischeck/${card.id}`} className="card-tile">
                  <div style={{ padding: "8px 8px 0", background: BG3 }}>
                    <div style={{ aspectRatio: "3/4", borderRadius: 12, overflow: "hidden", background: "#0D0D0D", display: "flex", alignItems: "center", justifyContent: "center", position: "relative" }}>
                      {imgSrc ? (
                        <img src={imgSrc} alt={card.name_de||card.name} loading="lazy"
                          style={{ width: "100%", height: "100%", objectFit: "contain" }}
                          onError={e => { (e.target as HTMLImageElement).style.display="none"; }}/>
                      ) : (
                        <div style={{ fontSize: 28, opacity: 0.1 }}>◎</div>
                      )}
                      <div style={{ position: "absolute", bottom: 5, right: 7, fontSize: 9, color: "rgba(237,233,224,0.25)", background: "rgba(0,0,0,0.5)", padding: "1px 5px", borderRadius: 4 }}>#{card.number}</div>
                    </div>
                  </div>
                  <div style={{ padding: "10px 12px 14px" }}>
                    <div style={{ fontSize: 12, fontWeight: 600, color: TX, whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis", marginBottom: 3 }}>{card.name_de || card.name}</div>
                    <div style={{ fontSize: 10, color: "rgba(237,233,224,0.3)", marginBottom: 6, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>{card.rarity || "–"}</div>
                    <div style={{ fontFamily: "monospace", fontSize: 14, fontWeight: 600, color: card.price_market ? GOLD : "rgba(237,233,224,0.25)" }}>
                      {card.price_market ? card.price_market.toLocaleString("de-DE", { minimumFractionDigits: 2 }) + " €" : "–"}
                    </div>
                  </div>
                </Link>
              );
            })
          )}
        </div>
      </div>
    </div>
  );
}

files.page_leaderboard.tsx:
"use client";
import { useState, useEffect } from "react";
import Link from "next/link";
import { createClient } from "@supabase/supabase-js";

const SB = createClient(process.env.NEXT_PUBLIC_SUPABASE_URL!, process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!);

export default function LeaderboardPage() {
  const [leaders, setLeaders] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [tab, setTab] = useState<"portfolio"|"trades"|"scans">("portfolio");

  useEffect(() => {
    async function load() {
      setLoading(true);
      try {
        if (tab === "trades") {
          const { data } = await SB.from("seller_stats")
            .select("user_id,total_sales,total_volume,avg_rating,profiles!seller_stats_user_id_fkey(username,avatar_url)")
            .order("total_volume", { ascending: false }).limit(20);
          setLeaders((data ?? []).map((d:any) => ({ ...d, profiles: Array.isArray(d.profiles)?d.profiles[0]:d.profiles })));
        } else if (tab === "scans") {
          const { data } = await SB.from("profiles")
            .select("id,username,scan_count").order("scan_count", { ascending: false }).limit(20);
          setLeaders(data ?? []);
        } else {
          const { data } = await SB.from("profiles")
            .select("id,username,avatar_url").limit(20);
          setLeaders(data ?? []);
        }
      } catch {}
      setLoading(false);
    }
    load();
  }, [tab]);

  const medals = ["🥇","🥈","🥉"];

  return (
    <div style={{ background:"#0A0A0A", minHeight:"100vh", color:"#EDE9E0" }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Playfair+Display:wght@400;500;700&display=swap');
        .ph { font-family:'Playfair Display',serif; letter-spacing:-0.05em; }
        .tab-btn { padding:10px 24px; border-radius:100px; border:1px solid transparent; font-size:13px; cursor:pointer; transition:all 0.2s; background:transparent; }
        .tab-btn.active { background:rgba(201,166,107,0.1); border-color:rgba(201,166,107,0.3); color:#C9A66B; font-weight:600; }
        .tab-btn:not(.active) { color:rgba(237,233,224,0.5); }
        .tab-btn:not(.active):hover { color:#EDE9E0; }
        .leader-row { display:flex; align-items:center; gap:16px; padding:16px 24px; background:#111111; border:1px solid rgba(255,255,255,0.06); border-radius:16px; transition:border-color 0.2s; }
        .leader-row:hover { border-color:rgba(201,166,107,0.2); }
        .leader-row.top3 { border-color:rgba(201,166,107,0.2); background:linear-gradient(135deg,rgba(201,166,107,0.06),#111111); }
        @keyframes skeleton { 0%,100%{opacity:.3} 50%{opacity:.6} }
      `}</style>

      <div style={{ maxWidth:800, margin:"0 auto", padding:"clamp(60px,8vw,100px) clamp(20px,4vw,48px)" }}>
        <div style={{ marginBottom:48 }}>
          <div style={{ fontSize:11, fontWeight:600, letterSpacing:"0.16em", textTransform:"uppercase", color:"rgba(201,166,107,0.7)", marginBottom:16 }}>Hall of Fame</div>
          <h1 className="ph" style={{ fontSize:"clamp(40px,6vw,72px)", fontWeight:500, color:"#EDE9E0", lineHeight:1 }}>
            Leaderboard
          </h1>
        </div>

        {/* Tabs */}
        <div style={{ display:"flex", gap:8, marginBottom:40, flexWrap:"wrap" }}>
          {[["portfolio","Portfolio"],["trades","Händler"],["scans","Scanner"]].map(([v,l]) => (
            <button key={v} className={`tab-btn${tab===v?" active":""}`} onClick={() => setTab(v as any)}>{l}</button>
          ))}
        </div>

        {/* List */}
        {loading ? (
          <div style={{ display:"flex", flexDirection:"column", gap:8 }}>
            {Array.from({length:8}).map((_,i) => (
              <div key={i} style={{ height:72, background:"#111", borderRadius:16, opacity:0.4, animation:"skeleton 1.5s ease-in-out infinite" }}/>
            ))}
          </div>
        ) : (
          <div style={{ display:"flex", flexDirection:"column", gap:8 }}>
            {leaders.map((l, i) => {
              const username = l.username || l.profiles?.username || "Anonym";
              const isTop3 = i < 3;
              return (
                <Link key={l.id||l.user_id||i} href={`/profil/${username}`} style={{ textDecoration:"none" }}>
                  <div className={`leader-row${isTop3?" top3":""}`}>
                    <div style={{ fontSize:isTop3?24:16, width:36, textAlign:"center", flexShrink:0 }}>
                      {isTop3 ? medals[i] : <span style={{ fontFamily:"monospace", color:"rgba(201,166,107,0.4)", fontSize:13 }}>#{i+1}</span>}
                    </div>
                    <div style={{ width:40, height:40, borderRadius:"50%", background:"rgba(201,166,107,0.1)", border:"1px solid rgba(201,166,107,0.2)", display:"flex", alignItems:"center", justifyContent:"center", fontSize:16, fontWeight:700, color:"#C9A66B", flexShrink:0 }}>
                      {username[0]?.toUpperCase()}
                    </div>
                    <div style={{ flex:1 }}>
                      <div style={{ fontSize:15, fontWeight:600, color:"#EDE9E0" }}>@{username}</div>
                      {tab==="trades" && l.total_volume && (
                        <div style={{ fontSize:12, color:"rgba(237,233,224,0.5)" }}>{l.total_sales} Verkäufe · {l.total_volume?.toFixed(0)} €</div>
                      )}
                      {tab==="scans" && l.scan_count && (
                        <div style={{ fontSize:12, color:"rgba(237,233,224,0.5)" }}>{l.scan_count} Scans</div>
                      )}
                    </div>
                    {isTop3 && (
                      <div style={{ fontSize:11, color:"#C9A66B", fontWeight:600, letterSpacing:"0.1em" }}>
                        {i===0?"CHAMPION":i===1?"VIZE":"BRONZE"}
                      </div>
                    )}
                  </div>
                </Link>
              );
            })}
          </div>
        )}
      </div>
    </div>
  );
}

files.page_login.tsx:
"use client";
import { useState } from "react";
import Link from "next/link";
import { createClient } from "@/lib/supabase/client";
import { useRouter } from "next/navigation";

export default function LoginPage() {
  const router = useRouter();
  const [email,    setEmail]    = useState("");
  const [password, setPassword] = useState("");
  const [loading,  setLoading]  = useState(false);
  const [error,    setError]    = useState("");

  async function submit(e: React.FormEvent) {
    e.preventDefault();
    setError(""); setLoading(true);
    const sb = createClient();
    const { error: e2 } = await sb.auth.signInWithPassword({ email, password });
    if (e2) { setError(e2.message); setLoading(false); return; }
    router.push("/dashboard");
  }

  return (
    <div style={{ background:"#0A0A0A", minHeight:"100vh", color:"#EDE9E0", display:"flex", alignItems:"center", justifyContent:"center", padding:"40px 20px" }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Playfair+Display:wght@400;500;700&display=swap');
        .ph { font-family:'Playfair Display',serif; letter-spacing:-0.05em; }
        .input-dark { width:100%; padding:16px 20px; background:rgba(255,255,255,0.04); border:1px solid rgba(255,255,255,0.1); border-radius:100px; color:#EDE9E0; font-size:15px; outline:none; transition:border-color 0.2s; font-family:inherit; }
        .input-dark:focus { border-color:rgba(201,166,107,0.5); }
        .input-dark::placeholder { color:rgba(237,233,224,0.3); }
