              <button onClick={() => setTab("wishlist")} style={{ padding: "13px 28px", background: GOLD, color: BG, borderRadius: 100, border: "none", fontSize: 14, fontWeight: 600, cursor: "pointer" }}>
                Zur Wunschliste
              </button>
            </div>
          ) : (
            <div style={{ display: "flex", flexDirection: "column", gap: 12 }}>
              {matches.map(m => {
                const card    = m.cards;
                const listing = m.marketplace_listings;
                if (!card) return null;
                const imgSrc  = card.image_url?.includes(".") ? card.image_url : (card.image_url ? card.image_url + "/low.webp" : null);
                const isCheap = listing?.price && card.price_market && listing.price < card.price_market * 0.97;
                return (
                  <div key={m.id} className="match-row">
                    {/* Gold line top */}
                    <div style={{ position: "absolute" }}/>
                    {/* Card image */}
                    <Link href={`/preischeck/${card.id}`} style={{ textDecoration: "none", flexShrink: 0 }}>
                      <div style={{ width: 56, height: 78, borderRadius: 8, overflow: "hidden", background: BG3, border: "1px solid rgba(201,166,107,0.15)" }}>
                        {imgSrc && <img src={imgSrc} alt="" style={{ width: "100%", height: "100%", objectFit: "contain" }}/>}
                      </div>
                    </Link>

                    <div style={{ flex: 1, minWidth: 0 }}>
                      <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 4 }}>
                        <span style={{ fontSize: 11, fontWeight: 700, color: GOLD, letterSpacing: "0.08em" }}>✦ MATCH GEFUNDEN</span>
                        {!m.notified && <span style={{ width: 6, height: 6, borderRadius: "50%", background: "#3db87a", flexShrink: 0 }}/>}
                      </div>
                      <Link href={`/preischeck/${card.id}`} style={{ textDecoration: "none" }}>
                        <div style={{ fontSize: 15, fontWeight: 600, color: TX, marginBottom: 2 }}>{card.name_de || card.name}</div>
                      </Link>
                      <div style={{ fontSize: 12, color: "rgba(237,233,224,0.4)" }}>
                        {card.set_id?.toUpperCase()} · @{listing?.profiles?.username ?? "Anonym"} · {listing?.condition ?? "NM"}
                      </div>
                    </div>

                    <div style={{ textAlign: "right", flexShrink: 0 }}>
                      <div className="ph" style={{ fontSize: 22, fontWeight: 500, color: GOLD, marginBottom: 4 }}>
                        {listing?.price?.toFixed(2)} €
                      </div>
                      {card.price_market && listing?.price && (
                        <div style={{ fontSize: 11, color: isCheap ? "#3db87a" : "rgba(237,233,224,0.35)", marginBottom: 10 }}>
                          Marktwert: {card.price_market.toFixed(2)} €
                        </div>
                      )}
                      <Link href="/marketplace" className="btn-gold">Kaufen ✦</Link>
                    </div>
                  </div>
                );
              })}
            </div>
          )
        )}
      </div>
    </div>
  );
}

files.profil_page.tsx:
import { createClient } from "@/lib/supabase/server";
import { notFound } from "next/navigation";
import Link from "next/link";
import type { Metadata } from "next";

interface Props { params: Promise<{ username: string }> }

export async function generateMetadata({ params }: Props): Promise<Metadata> {
  const { username } = await params;
  return {
    title: `@${username} — pokédax`,
    description: `Pokémon TCG Sammler @${username} auf pokédax`,
    openGraph: {
      title: `@${username} auf pokédax`,
      images: [`/api/og/profile/${username}`],
    },
  };
}

export default async function ProfilPage({ params }: Props) {
  const { username } = await params;
  const supabase = await createClient();

  const { data: profile } = await supabase
    .from("profiles")
    .select("id,username,avatar_url,created_at,is_premium")
    .eq("username", username)
    .single();

  if (!profile) notFound();

  const [
    { count: cardCount },
    { count: tradeCount },
    { data: badges },
    { data: topCards },
    { data: sellerStats },
  ] = await Promise.all([
    supabase.from("user_collection").select("id", { count: "exact", head: true }).eq("user_id", profile.id),
    supabase.from("escrow_transactions").select("id", { count: "exact", head: true })
      .or(`buyer_id.eq.${profile.id},seller_id.eq.${profile.id}`)
      .eq("status", "released"),
    supabase.from("user_badges").select("id,badge_key,label,icon,awarded_at").eq("user_id", profile.id).limit(10),
    supabase.from("user_collection")
      .select("cards(id,name,name_de,image_url,price_market)")
      .eq("user_id", profile.id).limit(6),
    supabase.from("seller_stats").select("*").eq("user_id", profile.id).single(),
  ]);

  const topCardsFlat = (topCards ?? [])
    .map((c: any) => Array.isArray(c.cards) ? c.cards[0] : c.cards)
    .filter(Boolean);

  const memberSince = new Date(profile.created_at).toLocaleDateString("de-DE", { month: "long", year: "numeric" });
  const initial = username[0]?.toUpperCase() ?? "U";

  const GOLD  = "#C9A66B";
  const BG    = "#0A0A0A";
  const BG2   = "#111111";
  const BG3   = "#1A1A1A";
  const TX    = "#EDE9E0";
  const TX2   = "rgba(237,233,224,0.7)";
  const GD2   = "rgba(201,166,107,0.7)";

  return (
    <div style={{ background: BG, minHeight: "100vh", color: TX }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Playfair+Display:wght@400;500;700&family=Instrument+Sans:wght@400;500;600&display=swap');
        .ph { font-family:'Playfair Display',serif; letter-spacing:-0.05em; }
        .card-tile { background:#111111; border:1px solid rgba(255,255,255,0.07); border-radius:16px; overflow:hidden; text-decoration:none; display:block; transition:transform 0.2s,border-color 0.2s; }
        .card-tile:hover { transform:translateY(-3px); border-color:rgba(201,166,107,0.2); }
        .badge-chip { display:inline-flex; align-items:center; gap:6px; padding:6px 14px; background:rgba(201,166,107,0.08); border:1px solid rgba(201,166,107,0.2); border-radius:100px; font-size:12px; font-weight:600; color:#C9A66B; }
      `}</style>

      <div style={{ maxWidth: 960, margin: "0 auto", padding: "clamp(60px,8vw,100px) clamp(20px,4vw,48px)" }}>

        {/* Profile header */}
        <div style={{ display: "flex", gap: 32, alignItems: "flex-start", marginBottom: 64, flexWrap: "wrap" }}>
          {/* Avatar */}
          <div style={{
            width: 96, height: 96, borderRadius: "50%", flexShrink: 0,
            background: "rgba(201,166,107,0.12)",
            border: `2px solid rgba(201,166,107,0.3)`,
            display: "flex", alignItems: "center", justifyContent: "center",
            fontSize: 36, fontWeight: 700, color: GOLD,
          }}>
            {initial}
          </div>

          <div style={{ flex: 1 }}>
            <div style={{ display: "flex", alignItems: "center", gap: 12, flexWrap: "wrap", marginBottom: 8 }}>
              <h1 className="ph" style={{ fontSize: "clamp(32px,4vw,52px)", fontWeight: 500, color: TX, lineHeight: 1 }}>
                @{username}
              </h1>
              {profile.is_premium && (
                <span style={{ padding: "4px 14px", background: "rgba(201,166,107,0.12)", border: "1px solid rgba(201,166,107,0.3)", borderRadius: 100, fontSize: 11, fontWeight: 700, color: GOLD, letterSpacing: "0.1em" }}>
                  ✦ PREMIUM
                </span>
              )}
            </div>
            <div style={{ fontSize: 13, color: "rgba(237,233,224,0.4)", marginBottom: 20 }}>
              Mitglied seit {memberSince}
            </div>

            {/* Stats row */}
            <div style={{ display: "flex", gap: 32, flexWrap: "wrap" }}>
              {[
                { n: (cardCount ?? 0).toString(), l: "Karten" },
                { n: (tradeCount ?? 0).toString(), l: "Trades" },
                { n: (sellerStats?.data?.avg_rating ?? "–").toString(), l: "Bewertung" },
              ].map(({ n, l }) => (
                <div key={l}>
                  <div className="ph" style={{ fontSize: 28, fontWeight: 500, color: GOLD, lineHeight: 1, marginBottom: 2 }}>{n}</div>
                  <div style={{ fontSize: 11, fontWeight: 600, letterSpacing: "0.1em", textTransform: "uppercase", color: "rgba(237,233,224,0.4)" }}>{l}</div>
                </div>
              ))}
            </div>
          </div>
        </div>

        {/* Badges */}
        {(badges ?? []).length > 0 && (
          <div style={{ marginBottom: 48 }}>
            <div style={{ fontSize: 11, fontWeight: 600, letterSpacing: "0.14em", textTransform: "uppercase", color: GD2, marginBottom: 16 }}>Badges</div>
            <div style={{ display: "flex", gap: 8, flexWrap: "wrap" }}>
              {(badges ?? []).map((b: any) => (
                <div key={b.id} className="badge-chip">
                  {b.icon && <span>{b.icon}</span>}
                  {b.label}
                </div>
              ))}
            </div>
          </div>
        )}

        {/* Top cards */}
        {topCardsFlat.length > 0 && (
          <div style={{ marginBottom: 48 }}>
            <div style={{ width: "100%", height: 1, background: "linear-gradient(90deg,transparent,rgba(201,166,107,0.2),transparent)", marginBottom: 32 }}/>
            <div style={{ fontSize: 11, fontWeight: 600, letterSpacing: "0.14em", textTransform: "uppercase", color: GD2, marginBottom: 20 }}>
              Sammlung
            </div>
            <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill,minmax(140px,1fr))", gap: 12 }}>
              {topCardsFlat.map((card: any) => {
                const img = card.image_url?.includes(".") ? card.image_url : (card.image_url ? card.image_url + "/low.webp" : null);
                return (
                  <Link key={card.id} href={`/preischeck/${card.id}`} className="card-tile">
                    <div style={{ aspectRatio: "3/4", background: BG3, display: "flex", alignItems: "center", justifyContent: "center", overflow: "hidden" }}>
                      {img && <img src={img} alt={card.name} style={{ width: "85%", height: "85%", objectFit: "contain" }} loading="lazy"/>}
                    </div>
                    <div style={{ padding: "8px 10px" }}>
                      <div style={{ fontSize: 11, fontWeight: 600, color: TX, whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis" }}>{card.name_de || card.name}</div>
                      {card.price_market && <div style={{ fontFamily: "monospace", fontSize: 12, color: GOLD }}>{card.price_market.toFixed(2)} €</div>}
                    </div>
                  </Link>
                );
              })}
            </div>
          </div>
        )}

        {/* Seller stats */}
        {sellerStats?.data && sellerStats.data.total_sales > 0 && (
          <div>
            <div style={{ width: "100%", height: 1, background: "linear-gradient(90deg,transparent,rgba(201,166,107,0.2),transparent)", marginBottom: 32 }}/>
            <div style={{ fontSize: 11, fontWeight: 600, letterSpacing: "0.14em", textTransform: "uppercase", color: GD2, marginBottom: 20 }}>Händler-Profil</div>
            <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit,minmax(160px,1fr))", gap: 12 }}>
              {[
                { l: "Verkäufe",     v: sellerStats.data.total_sales?.toString() ?? "0"          },
                { l: "Volumen",      v: (sellerStats.data.total_volume ?? 0).toFixed(0) + " €"   },
                { l: "Bewertung",    v: (sellerStats.data.avg_rating ?? 0).toFixed(1) + " / 5"  },
                { l: "Reaktionsrate",v: (sellerStats.data.response_rate ?? 0).toFixed(0) + " %" },
              ].map(({ l, v }) => (
                <div key={l} style={{ background: BG2, borderRadius: 16, padding: "20px", border: "1px solid rgba(255,255,255,0.07)" }}>
                  <div style={{ fontSize: 10, fontWeight: 600, letterSpacing: "0.12em", textTransform: "uppercase", color: GD2, marginBottom: 8 }}>{l}</div>
                  <div className="ph" style={{ fontSize: 24, fontWeight: 500, color: GOLD }}>{v}</div>
                </div>
              ))}
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

files.globals.css:
@import url("https://fonts.googleapis.com/css2?family=Inter:opsz,wght@14..32,300;14..32,400;14..32,500;14..32,600&family=DM+Mono:wght@400;500&display=swap");
@import url("https://api.fontshare.com/v2/css?f[]=satoshi@300,400,500&display=swap");
@tailwind base;
@tailwind components;
@tailwind utilities;

:root {
  /* ── Obsidian Heritage ── */
  --canvas:  #0A0A0C;
  --bg-1:    #16161A;
  --bg-2:    #1C1C21;
  --bg-3:    #222228;
  --br-1:    rgba(255,255,255,0.045);
  --br-2:    rgba(255,255,255,0.085);
  --br-3:    rgba(255,255,255,0.13);
  --tx-1:    #F8F6F2;
  --tx-2:    #BEB9B0;
  --tx-3:    #6E6B66;
  /* Teal — primärer Akzent */
  --accent:    #C9A66B;
  --accent-25: rgba(201,166,107,0.25);
  --accent-15: rgba(201,166,107,0.15);
  --accent-08: rgba(201,166,107,0.08);
  --accent-04: rgba(201,166,107,0.04);
  /* Champagne-Gold — Preise & Premium */
  --gold:      #EFD7A8;
  --gold-25:   rgba(239,215,168,0.25);
  --gold-15:   rgba(239,215,168,0.15);
  --gold-08:   rgba(239,215,168,0.08);
  /* Legacy */
  --gold-40:   rgba(201,166,107,0.40);
  --gold-04:   rgba(201,166,107,0.04);
  --green:   #3db87a;
  --red:     #dc4a5a;
  --font-display: 'Satoshi', 'Inter', system-ui, sans-serif;
  --font-body:    'Inter', system-ui, sans-serif;
  --font-mono:    'DM Mono', 'Fira Mono', monospace;
  --ease:    cubic-bezier(0.22, 1, 0.36, 1);
  --ease-in: cubic-bezier(0.4, 0, 1, 1);
}

*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
html { scroll-behavior: smooth; -webkit-text-size-adjust: 100%; }

body {
  background-color: var(--canvas);
  background-image:
    radial-gradient(ellipse 80% 50% at 15% 20%, rgba(201,166,107,0.09) 0%, transparent 60%),
    radial-gradient(ellipse 60% 40% at 85% 75%, rgba(201,166,107,0.07) 0%, transparent 55%),
    radial-gradient(ellipse 40% 30% at 50% 100%, rgba(201,166,107,0.05) 0%, transparent 50%);
  background-attachment: fixed;
  color: var(--tx-1);
  font-family: var(--font-body);
  font-size: 16px;
  line-height: 1.65;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
  overflow-x: hidden;
}

::-webkit-scrollbar { width: 2px; }
::-webkit-scrollbar-thumb { background: rgba(201,166,107,0.18); border-radius: 2px; }

/* ── Keyframes ── */
@keyframes blink         { 0%,100%{opacity:1} 50%{opacity:.12} }
@keyframes ticker-scroll { from{transform:translateX(0)} to{transform:translateX(-50%)} }
@keyframes fade-up       { from{opacity:0;transform:translateY(20px)} to{opacity:1;transform:translateY(0)} }
@keyframes pulse         { 0%,100%{opacity:.35} 50%{opacity:.55} }
@keyframes spin          { from{transform:rotate(0deg)} to{transform:rotate(360deg)} }
@keyframes shimmer       { from{background-position:200% 0} to{background-position:-200% 0} }

/* ══════════════════════════════════════════════════════
   GOLD GLOW — sanft, warm, elegant
   Kein harter Ring. Reines weiches Leuchten.
   ══════════════════════════════════════════════════════ */
.gold-glow {
  position: relative;
  overflow: hidden;
  transition:
    transform  0.65s var(--ease),
    box-shadow 0.65s var(--ease),
    border-color 0.3s;
}
.gold-glow::before {
  content: '';
  position: absolute;
  inset: -80%;
  background: radial-gradient(
    ellipse 70% 70% at center,
    rgba(201,166,107,0.38) 0%,
    rgba(201,166,107,0.12) 40%,
    transparent 72%
  );
  opacity: 0;
  transition: opacity 0.65s var(--ease), transform 0.65s var(--ease);
  z-index: 0;
  border-radius: inherit;
  pointer-events: none;
}
.gold-glow:hover::before {
  opacity: 1;
  transform: scale(1.15);
}
.gold-glow:hover {
  transform: translateY(-6px);
  box-shadow:
    0 2px 0 rgba(201,166,107,0.20),
    0 20px 60px -12px rgba(201,166,107,0.35),
    0 40px 100px -20px rgba(201,166,107,0.18);
  border-color: rgba(201,166,107,0.28) !important;
}
.gold-glow > * { position: relative; z-index: 1; }

/* card-hover — identisch, aber etwas stärker für Karten */
.card-hover {
  position: relative;
  overflow: hidden;
  transition:
    transform  0.65s var(--ease),
    box-shadow 0.65s var(--ease),
    border-color 0.3s;
}
.card-hover::before {
  content: '';
  position: absolute;
  inset: -80%;
  background: radial-gradient(
    ellipse 70% 70% at center,
    rgba(201,166,107,0.35) 0%,
    rgba(201,166,107,0.10) 45%,
    transparent 72%
  );
  opacity: 0;
  transition: opacity 0.65s var(--ease), transform 0.65s var(--ease);
  z-index: 0;
  pointer-events: none;
}
.card-hover:hover::before {
  opacity: 1;
  transform: scale(1.1);
}
.card-hover:hover {
  transform: translateY(-8px) scale(1.015);
  box-shadow:
    0 2px 0 rgba(201,166,107,0.15),
    0 24px 56px -12px rgba(201,166,107,0.32),
    0 48px 96px -24px rgba(201,166,107,0.14);
  border-color: rgba(201,166,107,0.22) !important;
}
.card-hover > * { position: relative; z-index: 1; }

/* ── Mobile ── */
@media (max-width: 768px) {
  .gold-glow:hover, .card-hover:hover {
    transform: translateY(-3px);
    box-shadow: 0 12px 32px -8px rgba(201,166,107,0.28);
  }
  button, a[href] { min-height: 44px; }
}
@media (max-width: 480px) {
  .gold-glow:hover, .card-hover:hover {
    transform: none;
    box-shadow: 0 0 0 1px rgba(201,166,107,0.25);
  }
}

/* ── Nav desktop/mobile ── */
.nav-desktop { display: flex !important; }
.nav-mobile  { display: none  !important; }
@media (max-width: 768px) {
  .nav-desktop { display: none  !important; }
  .nav-mobile  { display: flex  !important; }
}

/* NUCLEAR: Hide any rogue canvas backgrounds */
canvas[aria-hidden="true"] { display: none !important; pointer-events: none !important; }

/* ═══════════════════════════════════════════════════════
   MOBILE OVERRIDES — alle 8 Bugs aus den Screenshots
   ═══════════════════════════════════════════════════════ */
@media (max-width: 640px) {

  /* Fix 1: overflow-x global — verhindert horizontales Scrollen */
  body, #__next, main { overflow-x: hidden !important; }

  /* Fix 2: zwei-spalten-grids → einspaltigs */
  .grid-2col { grid-template-columns: 1fr !important; }

  /* Fix 3: Scanner-Sektion (home + /scanner) — 2-col → 1-col */
  .scanner-split {
    grid-template-columns: 1fr !important;
    min-height: unset !important;
  }
  .scanner-split > div:first-child {
    border-right: none !important;
    border-bottom: 1px solid rgba(255,255,255,0.06) !important;
  }

  /* Fix 4: Fantasy-Sektion (home) — 2-col → 1-col */
  .fantasy-split {
    grid-template-columns: 1fr !important;
    min-height: unset !important;
  }
  .fantasy-split > div:last-child { display: none !important; }

  /* Fix 5: Portfolio+Welcome (home) — 2-col → 1-col */
  .portfolio-welcome-grid {
    grid-template-columns: 1fr !important;
  }

  /* Fix 6: Forum-Cards (home) — 3-col → 1-col */
  .forum-cards-grid {
    grid-template-columns: 1fr !important;
  }

  /* Fix 7: Pricing-Grid (home + premium) — 3-col → 1-col */
  .pricing-plans-grid {
    grid-template-columns: 1fr !important;
  }

  /* Fix 8: Karten-Grid (home) — horizontal scroll statt 5-col */
  .cards-scroll-mobile {
    display: flex !important;
    overflow-x: auto !important;
    scroll-snap-type: x mandatory !important;
    gap: 10px !important;
    padding-bottom: 8px !important;
    -webkit-overflow-scrolling: touch !important;
  }
  .cards-scroll-mobile > * {
    flex-shrink: 0 !important;
    width: 140px !important;
    scroll-snap-align: start !important;
  }

  /* Fix 9: Footer — 4-col → 2-col auf mobile */
  .footer-grid-4col {
    grid-template-columns: 1fr 1fr !important;
    gap: 24px !important;
  }
  .footer-brand-col {
    grid-column: 1 / -1 !important;
  }

  /* Fix 10: Fantasy E-Mail Form — flex → column */
  .notify-form-row {
    flex-direction: column !important;
    gap: 10px !important;
  }
  .notify-form-row input,
  .notify-form-row button {
    width: 100% !important;
  }

  /* Fix 11: Portfolio stats grid — 4-col → 2-col */
  .portfolio-stats-grid {
    grid-template-columns: 1fr 1fr !important;
  }

  /* Fix 12: Section padding auf mobile reduzieren */
  .section-padding-mobile {
    padding-left: 16px !important;
    padding-right: 16px !important;
  }

  /* Fix 13: Portfolio page — content nicht abschneiden */
  .portfolio-header {
    padding: 24px 16px !important;
    overflow: hidden !important;
  }
  .portfolio-username {
    font-size: clamp(22px, 6vw, 40px) !important;
    word-break: break-word !important;
  }
}

/* Tablet: 641–1024px */
@media (min-width: 641px) and (max-width: 1024px) {
  .pricing-plans-grid {
    grid-template-columns: 1fr 1fr !important;
  }
  .footer-grid-4col {
    grid-template-columns: 1fr 1fr !important;
  }
}

/* ===================================
   MICRO-INTERACTIONS
   =================================== */

/* Card 3D hover tilt */
.card-hover {
  transition: transform 0.2s ease, box-shadow 0.2s ease;
  transform-style: preserve-3d;
  perspective: 1000px;
}
.card-hover:hover {
  transform: translateY(-4px) rotateX(2deg);
  box-shadow: 0 16px 48px rgba(0,0,0,0.5), 0 0 0 0.5px rgba(201,166,107,0.2);
}

/* Upvote pulse animation */
@keyframes upvote-pulse {
  0%   { transform: scale(1); }
  30%  { transform: scale(1.4); color: #C9A66B; }
  60%  { transform: scale(0.9); }
  100% { transform: scale(1); }
}
.upvote-btn:active {
  animation: upvote-pulse 0.35s ease;
}

/* Gold shimmer for premium elements */
@keyframes gold-shimmer {
  0%   { background-position: -200% center; }
  100% { background-position: 200% center; }
}
.gold-shimmer {
  background: linear-gradient(90deg, transparent, rgba(201,166,107,0.4), transparent);
  background-size: 200% auto;
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  animation: gold-shimmer 3s linear infinite;
}

/* Fade-in for page content */
@keyframes fade-in-up {
  from { opacity: 0; transform: translateY(12px); }
  to   { opacity: 1; transform: translateY(0); }
}
.fade-in {
  animation: fade-in-up 0.4s ease-out forwards;
}

/* Skeleton loading pulse */
@keyframes skeleton-pulse {
  0%, 100% { opacity: 0.3; }
  50%       { opacity: 0.6; }
}
.skeleton {
  animation: skeleton-pulse 1.5s ease-in-out infinite;
  background: rgba(255,255,255,0.06);
  border-radius: 8px;
}

/* Scanner result reveal */
@keyframes scan-reveal {
  from { opacity: 0; transform: scale(0.95) translateY(8px); }
  to   { opacity: 1; transform: scale(1) translateY(0); }
}
.scan-reveal {
  animation: scan-reveal 0.5s cubic-bezier(0.34, 1.56, 0.64, 1) forwards;
}

/* Button press feel */
.btn-press:active {
  transform: scale(0.97);
  transition: transform 0.08s ease;
}

/* Smooth number transitions */
.number-change {
  transition: color 0.3s ease;
}

files.price_sync_cron.ts:
"use server";
import { createClient } from "@supabase/supabase-js";
import { NextResponse } from "next/server";

export async function GET(request: Request) {
  const { searchParams } = new URL(request.url);
  if (searchParams.get("secret") !== process.env.CRON_SECRET) {
    return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
  }
  const supabase = createClient(
    process.env.NEXT_PUBLIC_SUPABASE_URL!,
    process.env.SUPABASE_SERVICE_ROLE_KEY!
  );
  let synced = 0, errors = 0;
  const today = new Date().toISOString().split("T")[0];
  let from = 0;
  while (true) {
    const { data: cards, error } = await supabase
      .from("cards").select("id,price_market,price_low,price_avg7")
      .not("price_market","is",null).range(from, from + 499);
    if (error || !cards?.length) break;
    const rows = cards.map(c => ({
      card_id:      c.id,
      recorded_at:  today,
      price_market: c.price_market,
      price_low:    c.price_low ?? null,
    }));
    const { error: e2 } = await supabase.from("price_history")
      .upsert(rows, { onConflict: "card_id,recorded_at", ignoreDuplicates: true });
    if (e2) { errors++; console.error(e2.message); }
    else synced += rows.length;
    if (cards.length < 500) break;
    from += 500;
  }
  return NextResponse.json({ synced, errors, date: today });
}

files.jp_bootstrap.ts:
"use server";
import { createClient } from "@supabase/supabase-js";
import { NextResponse } from "next/server";

const TCGDEX_BASE = "https://api.tcgdex.net/v2";
const JP_SETS = ["sv1s","sv2a","sv3a","sv4a","sv4k","sv5a","sv5k","sv6","sv6a","sv7","sv8","sv8a",
  "s1a","s1h","s2a","s3a","s4","s4a","s5a","s6a","s7d","s7r","s8","s8a","s9","s9a","s10","s10a","s10b","s11","s11a","s12"];

export async function GET(request: Request) {
  const { searchParams } = new URL(request.url);
  if (searchParams.get("secret") !== process.env.ADMIN_SECRET) {
    return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
  }

  const limit = parseInt(searchParams.get("limit") ?? "5");
  const supabase = createClient(
    process.env.NEXT_PUBLIC_SUPABASE_URL!,
    process.env.SUPABASE_SERVICE_ROLE_KEY!
  );

  let totalCards = 0, totalSets = 0;
  const setsToProcess = JP_SETS.slice(0, limit);

  for (const setId of setsToProcess) {
    try {
      // Fetch set info
      const setRes = await fetch(`${TCGDEX_BASE}/en/sets/${setId}`, {
        headers: { "User-Agent": "pokedax/1.0" }
      });
      if (!setRes.ok) continue;
      const setData = await setRes.json();

      // Upsert set
      await supabase.from("sets").upsert({
        id:           setId,
        name:         setData.name,
        name_de:      setData.name,
        series:       setData.serie?.name ?? "Japanese",
        card_count:   setData.cardCount ?? setData.cards?.length ?? 0,
        release_date: setData.releaseDate ?? null,
        logo_url:     setData.logo ?? null,
        image_url:    setData.logo ?? null,
        language:     "ja",
      }, { onConflict: "id" });

      totalSets++;

      // Fetch cards
      if (!setData.cards?.length) continue;
      const cards = setData.cards.slice(0, 200);

      for (let i = 0; i < cards.length; i += 50) {
        const chunk = cards.slice(i, i + 50);
        const rows = chunk.map((c: any) => ({
          id:        `${setId}-${c.localId}`,
          set_id:    setId,
          name:      c.name,
          name_de:   c.name,
          number:    String(c.localId),
          image_url: c.image ? `${c.image}/high.webp` : null,
          language:  "ja",
          category:  c.category ?? "Pokemon",
        }));
        await supabase.from("cards").upsert(rows, { onConflict: "id" });
        totalCards += rows.length;
      }
    } catch (err) {
      console.error(`Error processing ${setId}:`, err);
    }
  }

  return NextResponse.json({ totalSets, totalCards, setsProcessed: setsToProcess });
}
